INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(1, 'Siapakah penulis buku referensi Pramuka "Boyman"?', '["A. Sri Sultan Hamengkubuwono IX", "B. Baden Powell", "C. Andri Bob Sunardi", "D. Azrul Azwar"]'::jsonb, 'C. Andri Bob Sunardi'),
(1, 'Sifat kepramukaan yang penyelenggaraannya disesuaikan dengan keadaan dan kebutuhan masyarakat di negaranya adalah sifat...', '["A. Universal", "B. Nasional", "C. Internasional", "D. Fleksibel"]'::jsonb, 'B. Nasional'),
(1, 'Kepramukaan dapat berlaku untuk siapa saja dan diselenggarakan di mana saja. Ini disebut sifat...', '["A. Universal", "B. Nasional", "C. Internasional", "D. Terbuka"]'::jsonb, 'A. Universal'),
(1, 'Kepramukaan harus dapat mengembangkan rasa persaudaraan dan persahabatan antar sesama manusia. Ini adalah cerminan dari sifat...', '["A. Nasional", "B. Internasional", "C. Universal", "D. Mandiri"]'::jsonb, 'B. Internasional'),
(1, 'Fungsi kepramukaan bagi peserta didik (anak/pemuda) pada dasarnya adalah sebagai...', '["A. Kewajiban", "B. Pekerjaan", "C. Permainan yang menarik", "D. Pengabdian"]'::jsonb, 'C. Permainan yang menarik'),
(1, 'Bagi orang dewasa, kepramukaan bukan lagi permainan, melainkan suatu tugas yang memerlukan keikhlasan. Ini adalah fungsi sebagai...', '["A. Pekerjaan", "B. Pengabdian", "C. Kewajiban", "D. Hiburan"]'::jsonb, 'B. Pengabdian'),
(1, 'Kepramukaan berfungsi sebagai alat untuk memenuhi kebutuhan dan tujuan masyarakat. Ini adalah fungsi kepramukaan bagi...', '["A. Pemuda", "B. Pembina", "C. Orang Dewasa", "D. Masyarakat dan Organisasi"]'::jsonb, 'D. Masyarakat dan Organisasi'),
(1, 'Proses pendidikan di luar lingkungan sekolah dan keluarga dalam bentuk kegiatan menarik di alam terbuka disebut...', '["A. Gerakan Pramuka", "B. Kepramukaan", "C. Pramuka", "D. Kepanduan"]'::jsonb, 'B. Kepramukaan'),
(1, 'Orang-orang atau anggota yang mengikuti kegiatan dan tergabung di dalam organisasi kepanduan di Indonesia disebut...', '["A. Pramuka", "B. Gerakan Pramuka", "C. Kepramukaan", "D. Pandu"]'::jsonb, 'A. Pramuka'),
(1, 'Organisasi atau wadah resmi yang menyelenggarakan pendidikan kepramukaan di Indonesia adalah...', '["A. Kepanduan Nasional", "B. Kepramukaan", "C. Gerakan Pramuka", "D. Pramuka Garuda"]'::jsonb, 'C. Gerakan Pramuka'),
(1, 'Kepanjangan dari PRAMUKA adalah...', '["A. Praja Muda Karana", "B. Pemuda Rajin Berkarya", "C. Praja Muda Karya", "D. Pandu Rakyat Muda"]'::jsonb, 'A. Praja Muda Karana'),
(1, 'Istilah Praja Muda Karana memiliki arti...', '["A. Pemuda yang suka bekerja keras", "B. Rakyat muda yang suka berkarya", "C. Pemuda yang berjiwa ksatria", "D. Rakyat muda yang mandiri"]'::jsonb, 'B. Rakyat muda yang suka berkarya'),
(1, 'Bapak Pramuka Indonesia adalah...', '["A. Soekarno", "B. Jenderal Soedirman", "C. Sri Sultan Hamengkubuwono IX", "D. Ki Hajar Dewantara"]'::jsonb, 'C. Sri Sultan Hamengkubuwono IX'),
(1, 'Bapak Pandu Dunia (Chief Scout of the World) adalah...', '["A. Lord Robert Baden Powell", "B. William Smyth", "C. Ernest Thompson Seton", "D. Daniel Carter Beard"]'::jsonb, 'A. Lord Robert Baden Powell'),
(1, 'Tujuan Gerakan Pramuka yang pertama adalah membentuk anggota pramuka agar memiliki kepribadian yang...', '["A. Kaya raya", "B. Cerdas secara akademis", "C. Beriman, bertakwa, dan berakhlak mulia", "D. Terkenal di masyarakat"]'::jsonb, 'C. Beriman, bertakwa, dan berakhlak mulia'),
(1, 'Tujuan Gerakan Pramuka yang kedua adalah agar anggota pramuka menjadi warga negara yang...', '["A. Bebas aturan", "B. Berjiwa Pancasila", "C. Suka merantau", "D. Cepat bekerja"]'::jsonb, 'B. Berjiwa Pancasila'),
(1, 'Salah satu pilar metode kepramukaan adalah "Learning by Doing", yang artinya...', '["A. Belajar di dalam kelas", "B. Belajar sambil melakukan", "C. Belajar melalui teori", "D. Belajar dari buku"]'::jsonb, 'B. Belajar sambil melakukan'),
(1, 'Penggolongan usia Pramuka Siaga adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'A. 7 - 10 tahun'),
(1, 'Penggolongan usia Pramuka Penggalang adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'B. 11 - 15 tahun'),
(1, 'Penggolongan usia Pramuka Penegak adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'C. 16 - 20 tahun'),
(1, 'Penggolongan usia Pramuka Pandega adalah...', '["A. 7 - 10 tahun", "B. 11 - 15 tahun", "C. 16 - 20 tahun", "D. 21 - 25 tahun"]'::jsonb, 'D. 21 - 25 tahun'),
(1, 'Kode Kehormatan bagi Pramuka Siaga terdiri dari...', '["A. Trisatya dan Dasadarma", "B. Dwisatya dan Dwidarma", "C. Pancasila", "D. Sumpah Pemuda"]'::jsonb, 'B. Dwisatya dan Dwidarma'),
(1, 'Kode Kehormatan bagi Pramuka Penggalang, Penegak, dan Pandega terdiri dari...', '["A. Dwisatya dan Dwidarma", "B. Trisatya dan Dasadarma", "C. Catur Darma", "D. Panca Darma"]'::jsonb, 'B. Trisatya dan Dasadarma'),
(1, 'Sistem Pendidikan Kepramukaan menggunakan Sistem Among yang digagas oleh...', '["A. Soekarno", "B. Baden Powell", "C. Ki Hajar Dewantara", "D. Sri Sultan HB IX"]'::jsonb, 'C. Ki Hajar Dewantara'),
(1, 'Semboyan Sistem Among di depan memberikan teladan adalah...', '["A. Ing Ngarso Sung Tulodo", "B. Ing Madyo Mangun Karso", "C. Tut Wuri Handayani", "D. Bhinneka Tunggal Ika"]'::jsonb, 'A. Ing Ngarso Sung Tulodo'),
(1, 'Semboyan Sistem Among di tengah membangun kemauan adalah...', '["A. Ing Ngarso Sung Tulodo", "B. Ing Madyo Mangun Karso", "C. Tut Wuri Handayani", "D. Rawe-rawe rantas"]'::jsonb, 'B. Ing Madyo Mangun Karso'),
(1, 'Semboyan Sistem Among di belakang memberikan dorongan adalah...', '["A. Ing Ngarso Sung Tulodo", "B. Ing Madyo Mangun Karso", "C. Tut Wuri Handayani", "D. Jer basuki mawa beya"]'::jsonb, 'C. Tut Wuri Handayani'),
(1, 'Satuan terkecil dalam Pramuka Siaga disebut...', '["A. Regu", "B. Sangga", "C. Barung", "D. Reka"]'::jsonb, 'C. Barung'),
(1, 'Satuan terkecil dalam Pramuka Penggalang disebut...', '["A. Barung", "B. Regu", "C. Sangga", "D. Kelompok"]'::jsonb, 'B. Regu'),
(1, 'Satuan terkecil dalam Pramuka Penegak disebut...', '["A. Reka", "B. Regu", "C. Barung", "D. Sangga"]'::jsonb, 'D. Sangga'),
(1, 'Satuan terkecil dalam Pramuka Pandega disebut...', '["A. Reka", "B. Sangga", "C. Regu", "D. Barung"]'::jsonb, 'A. Reka'),
(1, 'Kumpulan dari beberapa Barung dalam Siaga disebut...', '["A. Pasukan", "B. Perindukan", "C. Ambalan", "D. Racana"]'::jsonb, 'B. Perindukan'),
(1, 'Kumpulan dari beberapa Regu dalam Penggalang disebut...', '["A. Perindukan", "B. Pasukan", "C. Ambalan", "D. Gugus Depan"]'::jsonb, 'B. Pasukan'),
(1, 'Kumpulan dari beberapa Sangga dalam Penegak disebut...', '["A. Ambalan", "B. Racana", "C. Pasukan", "D. Perindukan"]'::jsonb, 'A. Ambalan'),
(1, 'Wadah pembinaan Pramuka Pandega di Perguruan Tinggi disebut...', '["A. Ambalan", "B. Racana", "C. Pasukan", "D. Kwartir"]'::jsonb, 'B. Racana'),
(1, 'Tanda kecakapan dalam kepramukaan dibagi menjadi dua, yaitu...', '["A. TKU dan TKK", "B. TKK dan TKG", "C. TKU dan TKA", "D. TKA dan TKG"]'::jsonb, 'A. TKU dan TKK'),
(1, 'TKU singkatan dari...', '["A. Tanda Kehormatan Umum", "B. Tanda Kecakapan Umum", "C. Tanda Keterampilan Umum", "D. Tanda Kepanduan Umum"]'::jsonb, 'B. Tanda Kecakapan Umum'),
(1, 'TKK singkatan dari...', '["A. Tanda Kecakapan Khusus", "B. Tanda Keterampilan Khusus", "C. Tanda Kehormatan Khusus", "D. Tanda Kesatria Khusus"]'::jsonb, 'A. Tanda Kecakapan Khusus'),
(1, 'Tingkatan TKU pada Pramuka Siaga adalah...', '["A. Ramu, Rakit, Terap", "B. Mula, Bantu, Tata", "C. Bantara, Laksana", "D. Purwa, Madya, Utama"]'::jsonb, 'B. Mula, Bantu, Tata'),
(1, 'Tingkatan TKU pada Pramuka Penggalang adalah...', '["A. Ramu, Rakit, Terap", "B. Mula, Bantu, Tata", "C. Bantara, Laksana", "D. Purwa, Madya, Utama"]'::jsonb, 'A. Ramu, Rakit, Terap'),
(1, 'Tingkatan TKU pada Pramuka Penegak adalah...', '["A. Bantara, Laksana", "B. Ramu, Rakit", "C. Mula, Bantu", "D. Taruna, Dewasa"]'::jsonb, 'A. Bantara, Laksana'),
(1, 'Tingkatan TKK (Tanda Kecakapan Khusus) dibagi menjadi 3 tingkatan, yaitu...', '["A. Mula, Bantu, Tata", "B. Ramu, Rakit, Terap", "C. Purwa, Madya, Utama", "D. Bawah, Menengah, Atas"]'::jsonb, 'C. Purwa, Madya, Utama'),
(1, 'Lambang Gerakan Pramuka Indonesia adalah...', '["A. Tunas Kelapa", "B. Bintang", "C. Padi dan Kapas", "D. Bunga Lily (Fleur-de-lis)"]'::jsonb, 'A. Tunas Kelapa'),
(1, 'Pencipta lambang Tunas Kelapa adalah...', '["A. H. Mutahar", "B. Soenardjo Atmodipuro", "C. C. Simanjuntak", "D. W.R. Supratman"]'::jsonb, 'B. Soenardjo Atmodipuro'),
(1, 'Bentuk lambang Pramuka Internasional (WOSM) adalah...', '["A. Tunas Kelapa", "B. Burung Elang", "C. Bunga Lily (Fleur-de-lis)", "D. Kompas"]'::jsonb, 'C. Bunga Lily (Fleur-de-lis)'),
(1, 'Gerakan Pramuka resmi diperkenalkan kepada rakyat Indonesia pada tanggal...', '["A. 14 Agustus 1961", "B. 20 Mei 1908", "C. 28 Oktober 1928", "D. 17 Agustus 1945"]'::jsonb, 'A. 14 Agustus 1961'),
(1, 'Oleh karena itu, Hari Pramuka di Indonesia diperingati setiap tanggal...', '["A. 14 Agustus", "B. 20 Mei", "C. 1 Juni", "D. 22 Desember"]'::jsonb, 'A. 14 Agustus'),
(1, 'Undang-Undang yang mengatur tentang Gerakan Pramuka saat ini adalah...', '["A. UU No. 20 Tahun 2003", "B. UU No. 12 Tahun 2010", "C. UU No. 14 Tahun 2005", "D. UU No. 40 Tahun 2009"]'::jsonb, 'B. UU No. 12 Tahun 2010'),
(1, 'Motto Gerakan Pramuka adalah...', '["A. Satyaku Kudarmakan, Darmaku Kubaktikan", "B. Berbakti dan Mengabdi", "C. Ikhlas Bakti Bina Bangsa", "D. Suci dalam pikiran, perkataan, dan perbuatan"]'::jsonb, 'A. Satyaku Kudarmakan, Darmaku Kubaktikan'),
(1, 'Tingkatan tertinggi dalam setiap golongan Pramuka yang telah memenuhi syarat pencapaian Garuda disebut...', '["A. Pramuka Utama", "B. Pramuka Teladan", "C. Pramuka Garuda", "D. Pramuka Mandiri"]'::jsonb, 'C. Pramuka Garuda');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(3, 'Nama lengkap Bapak Pandu Dunia adalah...', '["A. Robert Stephenson Smyth Baden-Powell", "B. William Smyth Baden-Powell", "C. George Stephenson Baden-Powell", "D. Robert Arthur Baden-Powell"]'::jsonb, 'A. Robert Stephenson Smyth Baden-Powell'),
(3, 'Baden-Powell lahir di kota...', '["A. Manchester", "B. Liverpool", "C. London", "D. Oxford"]'::jsonb, 'C. London'),
(3, 'Tanggal lahir Baden-Powell adalah...', '["A. 14 Agustus 1857", "B. 22 Februari 1857", "C. 20 Mei 1908", "D. 8 Januari 1857"]'::jsonb, 'B. 22 Februari 1857'),
(3, 'Nama ayah Baden-Powell adalah...', '["A. Prof. Domine Baden-Powell", "B. Admiral W.T. Smyth", "C. Lord George Powell", "D. Sir Arthur Baden"]'::jsonb, 'A. Prof. Domine Baden-Powell'),
(3, 'Profesi ayah Baden-Powell adalah seorang...', '["A. Perwira Angkatan Laut", "B. Guru Besar Geometri di Universitas Oxford", "C. Jenderal Angkatan Darat", "D. Dokter Bedah"]'::jsonb, 'B. Guru Besar Geometri di Universitas Oxford'),
(3, 'Nama ibu dari Baden-Powell adalah...', '["A. Olave St. Clair", "B. Agnes Smyth", "C. Miss Henrietta Grace Smyth", "D. Elizabeth Grace"]'::jsonb, 'C. Miss Henrietta Grace Smyth'),
(3, 'Ayah dari ibu Baden-Powell (kakek dari pihak ibu) adalah seorang laksamana bernama...', '["A. Admiral William T. Smyth", "B. Laksamana Nelson", "C. Admiral John Powell", "D. Laksamana Arthur"]'::jsonb, 'A. Admiral William T. Smyth'),
(3, 'Ayah Baden-Powell meninggal dunia ketika Baden-Powell berusia...', '["A. 3 tahun", "B. 5 tahun", "C. 7 tahun", "D. 10 tahun"]'::jsonb, 'A. 3 tahun'),
(3, 'Julukan Baden-Powell saat bersekolah di Charterhouse School karena kebiasaannya mandi air dingin adalah...', '["A. The Wolf", "B. Bathing Towel", "C. Stevey", "D. Little Robert"]'::jsonb, 'B. Bathing Towel'),
(3, 'Kepala sekolah di Charterhouse yang sangat berpengaruh terhadap pembentukan karakter Baden-Powell adalah...', '["A. Dr. Haig Brown", "B. Dr. William Smyth", "C. Prof. George", "D. Mayor Kenneth"]'::jsonb, 'A. Dr. Haig Brown'),
(3, 'Setelah lulus dari Charterhouse, Baden-Powell mengikuti ujian militer dan lulus kavaleri dengan urutan ke...', '["A. Satu", "B. Dua", "C. Tiga", "D. Empat"]'::jsonb, 'B. Dua'),
(3, 'Pasukan kavaleri yang pertama kali ditempati Baden-Powell di India adalah...', '["A. 1st Infantry", "B. 5th Royal", "C. 13th Hussars", "D. 8th Cavalry"]'::jsonb, 'C. 13th Hussars'),
(3, 'Baden-Powell pertama kali ditugaskan ke India sebagai prajurit muda pada tahun...', '["A. 1876", "B. 1880", "C. 1899", "D. 1900"]'::jsonb, 'A. 1876'),
(3, 'Pangkat pertama Baden-Powell saat bergabung di ketentaraan di India adalah...', '["A. Kapten", "B. Mayor", "C. Pembantu Letnan (Sub-Lieutenant)", "D. Kolonel"]'::jsonb, 'C. Pembantu Letnan (Sub-Lieutenant)'),
(3, 'Suku Zulu, Ashanti, dan Matabele di Afrika memberikan julukan khusus kepada Baden-Powell, yaitu...', '["A. Sang Macan", "B. Impeesa", "C. Mafeking", "D. Bwana"]'::jsonb, 'B. Impeesa'),
(3, 'Arti dari julukan "Impeesa" yang diberikan oleh suku di Afrika adalah...', '["A. Singa yang perkasa", "B. Burung elang yang tajam", "C. Serigala yang tidak pernah tidur", "D. Ksatria pemberani"]'::jsonb, 'C. Serigala yang tidak pernah tidur'),
(3, 'Baden-Powell berhasil mempertahankan sebuah kota dari kepungan bangsa Boer di Afrika Selatan selama 217 hari. Kota tersebut bernama...', '["A. Pretoria", "B. Cape Town", "C. Johannesburg", "D. Mafeking"]'::jsonb, 'D. Mafeking'),
(3, 'Peristiwa pengepungan kota Mafeking terjadi pada tahun...', '["A. 1876 - 1877", "B. 1899 - 1900", "C. 1907 - 1908", "D. 1914 - 1918"]'::jsonb, 'B. 1899 - 1900'),
(3, 'Buku panduan pelacakan militer yang ditulis Baden-Powell dan kelak disukai oleh anak-anak muda Inggris adalah...', '["A. Scouting for Boys", "B. Aids to Scouting", "C. Rovering to Success", "D. The Jungle Book"]'::jsonb, 'B. Aids to Scouting'),
(3, 'Buku "Aids to Scouting" diterbitkan pada tahun...', '["A. 1899", "B. 1907", "C. 1908", "D. 1910"]'::jsonb, 'A. 1899'),
(3, 'Perkemahan percobaan kepanduan pertama kali diadakan oleh Baden-Powell di sebuah pulau bernama...', '["A. Pulau Gilwell", "B. Pulau Brownsea", "C. Pulau Wight", "D. Pulau Britania"]'::jsonb, 'B. Pulau Brownsea'),
(3, 'Perkemahan di Pulau Brownsea yang menjadi tonggak sejarah kepramukaan dilaksanakan pada tahun...', '["A. 1899", "B. 1907", "C. 1908", "D. 1920"]'::jsonb, 'B. 1907'),
(3, 'Berapa jumlah anak laki-laki yang mengikuti perkemahan percobaan di Pulau Brownsea?', '["A. 15 anak", "B. 20 anak", "C. 22 anak", "D. 30 anak"]'::jsonb, 'C. 22 anak'),
(3, 'Teman tentara yang membantu Baden-Powell mengurus perkemahan di Pulau Brownsea adalah...', '["A. Mayor Kenneth McLaren", "B. Arthur Pearson", "C. William Smyth", "D. King Edward VII"]'::jsonb, 'A. Mayor Kenneth McLaren'),
(3, 'Buku panduan utama yang menjadi cikal bakal berdirinya gerakan kepanduan dunia adalah...', '["A. Aids to Scouting", "B. Rovering to Success", "C. Scouting for Boys", "D. Wolf Cub''s Handbook"]'::jsonb, 'C. Scouting for Boys'),
(3, 'Buku "Scouting for Boys" karya Baden-Powell pertama kali diterbitkan pada tahun...', '["A. 1907", "B. 1908", "C. 1910", "D. 1912"]'::jsonb, 'B. 1908'),
(3, 'Organisasi kepanduan putri (Girl Guides) pertama kali dibentuk dengan bantuan adik perempuan Baden-Powell yang bernama...', '["A. Olave Baden-Powell", "B. Henrietta Grace", "C. Agnes Baden-Powell", "D. Jessie Baden-Powell"]'::jsonb, 'C. Agnes Baden-Powell'),
(3, 'Organisasi Girl Guides (Kepanduan Putri) dirintis pada tahun...', '["A. 1908", "B. 1910", "C. 1912", "D. 1916"]'::jsonb, 'B. 1910'),
(3, 'Kepanduan untuk golongan anak-anak (Siaga/Wolf Cub) didirikan oleh Baden-Powell pada tahun...', '["A. 1908", "B. 1912", "C. 1916", "D. 1920"]'::jsonb, 'C. 1916'),
(3, 'Buku panduan yang digunakan Baden-Powell untuk menginspirasi golongan Siaga (Wolf Cub) adalah...', '["A. Scouting for Boys", "B. The Jungle Book", "C. Aids to Scouting", "D. Rovering to Success"]'::jsonb, 'B. The Jungle Book'),
(3, 'Penulis buku "The Jungle Book" yang menginspirasi pembentukan golongan Siaga adalah...', '["A. Rudyard Kipling", "B. Arthur Conan Doyle", "C. William Shakespeare", "D. J.K. Rowling"]'::jsonb, 'A. Rudyard Kipling'),
(3, 'Kepanduan untuk golongan pemuda (Penegak/Rover Scout) dibentuk pada tahun...', '["A. 1916", "B. 1918", "C. 1920", "D. 1922"]'::jsonb, 'B. 1918'),
(3, 'Buku panduan untuk Rover Scout yang ditulis oleh Baden-Powell pada tahun 1922 berjudul...', '["A. The Jungle Book", "B. Aids to Scouting", "C. Rovering to Success", "D. Scouting for Boys"]'::jsonb, 'C. Rovering to Success'),
(3, 'Jambore Kepanduan Dunia pertama kali diadakan di gedung...', '["A. Olympia Hall", "B. Wembley Stadium", "C. Royal Albert Hall", "D. Gilwell Park"]'::jsonb, 'A. Olympia Hall'),
(3, 'Jambore Dunia pertama diadakan di kota London pada tahun...', '["A. 1918", "B. 1920", "C. 1922", "D. 1924"]'::jsonb, 'B. 1920'),
(3, 'Pada malam terakhir Jambore Dunia pertama, Baden-Powell secara resmi diangkat menjadi...', '["A. Jenderal Pandu", "B. Raja Pandu", "C. Bapak Pandu Dunia (Chief Scout of the World)", "D. Presiden WOSM"]'::jsonb, 'C. Bapak Pandu Dunia (Chief Scout of the World)'),
(3, 'Gelar kehormatan "Lord" (Baron) dianugerahkan kepada Baden-Powell oleh Raja George V pada tahun...', '["A. 1920", "B. 1925", "C. 1929", "D. 1937"]'::jsonb, 'C. 1929'),
(3, 'Nama istri Baden-Powell yang kelak menjadi Chief Guide of the World adalah...', '["A. Agnes Smyth", "B. Olave St. Clair Soames", "C. Henrietta Grace", "D. Elizabeth Baden"]'::jsonb, 'B. Olave St. Clair Soames'),
(3, 'Baden-Powell pensiun dari dinas kemiliteran Inggris dengan pangkat terakhir...', '["A. Mayor Jenderal", "B. Letnan Jenderal", "C. Jenderal Penuh", "D. Marsekal"]'::jsonb, 'B. Letnan Jenderal'),
(3, 'Raja Inggris yang menyarankan Baden-Powell untuk pensiun dari militer agar bisa membesarkan Gerakan Kepanduan adalah...', '["A. Raja George V", "B. Raja George VI", "C. Raja Edward VII", "D. Ratu Victoria"]'::jsonb, 'C. Raja Edward VII'),
(3, 'Pada tahun 1919, W. de Bois Maclaren menyumbangkan sebidang tanah untuk pusat pelatihan pembina pramuka yang diberi nama...', '["A. Brownsea Island", "B. Mafeking Camp", "C. Gilwell Park", "D. Olympia Hall"]'::jsonb, 'C. Gilwell Park'),
(3, 'Kursus Pembina Pramuka (Wood Badge) pertama kali diselenggarakan di Gilwell Park pada tahun...', '["A. 1916", "B. 1919", "C. 1920", "D. 1922"]'::jsonb, 'B. 1919'),
(3, 'Kalung manik-manik kayu (Wood Badge) berasal dari kalung pimpinan suku Afrika yang pernah dikalahkan oleh Baden-Powell, bernama...', '["A. Zulu", "B. Dinizulu", "C. Ashanti", "D. Matabele"]'::jsonb, 'B. Dinizulu'),
(3, 'Simbol dari pusat pelatihan pembina Gilwell Park adalah...', '["A. Bunga Lily", "B. Tunas Kelapa", "C. Kapak menancap di balok kayu", "D. Serigala"]'::jsonb, 'C. Kapak menancap di balok kayu'),
(3, 'Baden-Powell menghabiskan masa tuanya dan meninggal dunia di negara...', '["A. Inggris", "B. Afrika Selatan", "C. India", "D. Kenya"]'::jsonb, 'D. Kenya'),
(3, 'Baden-Powell meninggal dunia pada tanggal...', '["A. 8 Januari 1941", "B. 22 Februari 1941", "C. 14 Agustus 1941", "D. 30 Oktober 1941"]'::jsonb, 'A. 8 Januari 1941'),
(3, 'Baden-Powell dimakamkan di pemakaman St. Peter, di kota...', '["A. London", "B. Cape Town", "C. Nyeri", "D. Nairobi"]'::jsonb, 'C. Nyeri'),
(3, 'Usia Baden-Powell saat meninggal dunia adalah...', '["A. 73 tahun", "B. 80 tahun", "C. 83 tahun", "D. 90 tahun"]'::jsonb, 'C. 83 tahun'),
(3, 'Pada batu nisan makam Baden-Powell terdapat tanda jejak kepanduan berupa lingkaran dengan titik di tengah yang memiliki arti...', '["A. Saya telah pulang", "B. Bahaya di depan", "C. Jalan terus", "D. Tunggu di sini"]'::jsonb, 'A. Saya telah pulang'),
(3, 'Organisasi kepanduan dunia saat ini bernaung di bawah organisasi bernama WOSM, singkatan dari...', '["A. World Organization of Scout Members", "B. World Organization of the Scout Movement", "C. World Order of Scout Movement", "D. World Organization of Scouting Men"]'::jsonb, 'B. World Organization of the Scout Movement');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(5, 'Bab 5 dalam buku referensi Boyman secara khusus membahas rangkuman dari buku legendaris karya Baden-Powell yang berjudul...', '["A. Rovering to Success", "B. Scouting for Boys", "C. Aids to Scouting", "D. The Wolf Cub''s Handbook"]'::jsonb, 'B. Scouting for Boys'),
(5, 'Buku Scouting for Boys pada dasarnya dibagi ke dalam beberapa sub-bab yang disebut dengan istilah...', '["A. Panduan Rimba", "B. Sesi Petualangan", "C. Cerita Api Unggun", "D. Kisah Penjelajah"]'::jsonb, 'C. Cerita Api Unggun'),
(5, 'Ada berapa total Cerita Api Unggun (Campfire Yarns) yang menjadi susunan utama materi Scouting for Boys?', '["A. 15 Cerita", "B. 21 Cerita", "C. 24 Cerita", "D. 26 Cerita"]'::jsonb, 'D. 26 Cerita'),
(5, 'Cerita Api Unggun ke-1 membahas sejarah tentang pasukan anak laki-laki di Afrika yang menjadi inspirasi kepanduan, yang disebut...', '["A. Mafeking Cadet Corps", "B. Brownsea Troops", "C. Boy Scouts of Africa", "D. The Wolf Cubs"]'::jsonb, 'A. Mafeking Cadet Corps'),
(5, 'Pemimpin pasukan anak-anak pada masa pengepungan Mafeking tersebut adalah...', '["A. Mayor Kenneth", "B. Lord Edward Cecil", "C. Jenderal Kitchener", "D. Arthur Pearson"]'::jsonb, 'B. Lord Edward Cecil'),
(5, 'Baden-Powell menyadari kehebatan pasukan anak-anak di Mafeking yang kemudian menjadi cikal bakal pentingnya peran kaum muda. Pengepungan kota Mafeking terjadi di negara...', '["A. Afrika Selatan", "B. Kenya", "C. India", "D. Inggris"]'::jsonb, 'A. Afrika Selatan'),
(5, 'Cerita Api Unggun ke-4 membahas inti dari sistem kepramukaan yang membagi anggota ke dalam kelompok kecil, disebut dengan...', '["A. Sistem Kelompok", "B. Sistem Pasukan", "C. Sistem Regu (Patrol System)", "D. Sistem Ambalan"]'::jsonb, 'C. Sistem Regu (Patrol System)'),
(5, 'Menurut gagasan awal Baden-Powell, jumlah anggota yang ideal dalam satu regu pramuka (patrol) adalah...', '["A. 3 sampai 5 orang", "B. 6 sampai 8 orang", "C. 10 sampai 12 orang", "D. 15 sampai 20 orang"]'::jsonb, 'B. 6 sampai 8 orang'),
(5, 'Sebutan untuk pemimpin regu dalam bahasa Inggris yang dicetuskan oleh Baden-Powell adalah...', '["A. Scout Leader", "B. Chief Scout", "C. Troop Leader", "D. Patrol Leader"]'::jsonb, 'D. Patrol Leader'),
(5, 'Cerita Api Unggun ke-8 membahas tentang keterampilan membuat bangunan darurat menggunakan kayu dan tali, yang dalam istilah kepramukaan disebut...', '["A. Pionering / Kepeloporan", "B. Navigasi Darat", "C. Bivak", "D. Survival"]'::jsonb, 'A. Pionering / Kepeloporan'),
(5, 'Simpul dasar dalam pionering yang berguna untuk menyambung dua utas tali yang sama besar dan tidak licin adalah...', '["A. Simpul Mati (Reef Knot)", "B. Simpul Hidup", "C. Simpul Anyam", "D. Simpul Delapan"]'::jsonb, 'A. Simpul Mati (Reef Knot)'),
(5, 'Simpul yang berguna untuk mengikat leher binatang agar tidak tercekik, serta sering menjadi simpul dasar penyelamatan adalah...', '["A. Simpul Pangkal", "B. Simpul Tarik", "C. Simpul Tiang (Bowline)", "D. Simpul Jangkar"]'::jsonb, 'C. Simpul Tiang (Bowline)'),
(5, 'Simpul yang paling sering digunakan untuk memulai dan mengakhiri sebuah ikatan pada tongkat pionering adalah...', '["A. Simpul Mati", "B. Simpul Pangkal (Clove Hitch)", "C. Simpul Kembar", "D. Simpul Ujung Tali"]'::jsonb, 'B. Simpul Pangkal (Clove Hitch)'),
(5, 'Simpul yang digunakan untuk menyambung dua utas tali yang ukurannya tidak sama besar dan dalam keadaan kering adalah...', '["A. Simpul Tarik", "B. Simpul Erat", "C. Simpul Nelayan", "D. Simpul Anyam (Sheet Bend)"]'::jsonb, 'D. Simpul Anyam (Sheet Bend)'),
(5, 'Ikatan yang digunakan untuk menggabungkan dua buah tongkat yang bersilangan tegak lurus (membentuk sudut 90 derajat) adalah...', '["A. Ikatan Palang (Square Lashing)", "B. Ikatan Silang (Diagonal Lashing)", "C. Ikatan Canggah", "D. Ikatan Kaki Tiga"]'::jsonb, 'A. Ikatan Palang (Square Lashing)'),
(5, 'Cerita Api Unggun ke-9 membahas mengenai kehidupan di alam terbuka, yaitu rutinitas...', '["A. Penjelajahan", "B. Perkemahan (Camping)", "C. Pendakian", "D. Susur Sungai"]'::jsonb, 'B. Perkemahan (Camping)'),
(5, 'Hal yang paling utama dan penting untuk diperhatikan saat memilih lokasi untuk mendirikan tenda perkemahan adalah...', '["A. Dekat dengan jalan raya besar", "B. Pemandangan yang indah", "C. Dekat sumber air bersih dan aman dari bahaya alam", "D. Berada di tanah yang landai dan berpasir"]'::jsonb, 'C. Dekat sumber air bersih dan aman dari bahaya alam'),
(5, 'Cerita Api Unggun ke-10 memberikan panduan teknis yang sangat dibutuhkan regu mandiri, yaitu tentang...', '["A. Masakan di Perkemahan (Camp Cooking)", "B. Pertolongan Pertama", "C. Navigasi Malam", "D. Tanda Bahaya"]'::jsonb, 'A. Masakan di Perkemahan (Camp Cooking)'),
(5, 'Salah satu makanan khas perkemahan ala Baden-Powell, di mana adonan tepung dililitkan pada sebatang kayu lalu dipanggang di atas bara api, disebut...', '["A. Roti Pandu", "B. Roti Lilit (Twist)", "C. Kue Api", "D. Biskuit Darurat"]'::jsonb, 'B. Roti Lilit (Twist)'),
(5, 'Cerita Api Unggun ke-11 dan 12 mengajarkan keterampilan mengasah kepekaan mata di alam terbuka, berupa...', '["A. Semboyan Isyarat", "B. Pengamatan Bintang", "C. Mencari dan Mengikuti Jejak (Tracking)", "D. Mengukur Ketinggian Pohon"]'::jsonb, 'C. Mencari dan Mengikuti Jejak (Tracking)'),
(5, 'Saat sedang mengikuti jejak di alam bebas, seorang Pramuka dianjurkan untuk berjalan dengan cara...', '["A. Berlari cepat agar tidak kehilangan jejak", "B. Membawa senjata tajam bersiaga penuh", "C. Sambil bernyanyi untuk menghilangkan rasa takut", "D. Tenang sambil memperhatikan keadaan tanah dan sekelilingnya"]'::jsonb, 'D. Tenang sambil memperhatikan keadaan tanah dan sekelilingnya'),
(5, 'Dalam sandi jejak Pramuka, susunan batu yang ditumpuk menjadi tiga bagian dan ditambahkan satu batu kecil di sebelah kanan memiliki arti...', '["A. Jalan ke arah kanan", "B. Ada air di sebelah kanan", "C. Rintangan di depan", "D. Tempat berkemah di kanan"]'::jsonb, 'A. Jalan ke arah kanan'),
(5, 'Sebuah lingkaran yang digambar di tanah dengan titik di tengahnya merupakan tanda jejak kepanduan yang berarti...', '["A. Bahaya, jangan melintas", "B. Air beracun", "C. Saya telah pulang / Kembali ke perkemahan", "D. Tunggu di sini"]'::jsonb, 'C. Saya telah pulang / Kembali ke perkemahan'),
(5, 'Cerita Api Unggun ke-13 menuntut seorang pandu untuk memiliki kemampuan observasi dan deduksi. Tokoh detektif fiksi yang sering dijadikan contoh oleh Baden-Powell untuk hal ini adalah...', '["A. Hercule Poirot", "B. Sherlock Holmes", "C. James Bond", "D. Inspektur Gadget"]'::jsonb, 'B. Sherlock Holmes'),
(5, 'Cerita Api Unggun ke-14 berjudul "Menyembunyikan Diri - Mengendap" (Stalking). Mengendap sangat berguna di alam bebas untuk...', '["A. Mendekati dan mengamati hewan liar tanpa disadari oleh hewan tersebut", "B. Menyerang musuh secara diam-diam", "C. Bersembunyi dari tugas perkemahan", "D. Bermain petak umpet dengan regu lain"]'::jsonb, 'A. Mendekati dan mengamati hewan liar tanpa disadari oleh hewan tersebut'),
(5, 'Aturan utama yang harus diperhatikan seorang Pramuka saat sedang mengendap mendekati target di alam liar adalah...', '["A. Memakai wewangian agar hewan tidak curiga", "B. Bergerak serah dengan hembusan angin", "C. Bergerak berlawanan arah dengan hembusan angin", "D. Membawa makanan untuk memancing hewan"]'::jsonb, 'C. Bergerak berlawanan arah dengan hembusan angin'),
(5, 'Cerita Api Unggun ke-15 dan 16 membahas apresiasi terhadap lingkungan hidup, yakni tentang pengetahuan...', '["A. Batuan dan Mineral", "B. Binatang dan Tumbuh-tumbuhan", "C. Cuaca dan Iklim", "D. Mata Air dan Sungai"]'::jsonb, 'B. Binatang dan Tumbuh-tumbuhan'),
(5, 'Prinsip konservasi dalam kepanduan menyatakan bahwa seorang Pramuka dilarang keras membunuh binatang apa pun, KECUALI...', '["A. Binatang tersebut memiliki bulu yang berharga", "B. Untuk dijadikan koleksi awetan", "C. Saat sedang mengikuti perlombaan berburu", "D. Ketika terancam bahaya atau terpaksa untuk bertahan hidup/makan"]'::jsonb, 'D. Ketika terancam bahaya atau terpaksa untuk bertahan hidup/makan'),
(5, 'Pengetahuan seorang Pramuka dalam mengenali berbagai jenis pohon liar, dedaunan, dan akar yang bisa dimakan sangat menunjang kemampuannya dalam bidang...', '["A. Survival (Bertahan Hidup)", "B. Navigasi Darat", "C. Pionering", "D. Pertolongan Pertama"]'::jsonb, 'A. Survival (Bertahan Hidup)'),
(5, 'Cerita Api Unggun ke-17 berjudul "Bagaimana Supaya Kuat", yang memberikan instruksi agar kaum muda terbiasa menjaga...', '["A. Ketahanan mental saat di-bully", "B. Kekuatan finansial di masa depan", "C. Kesehatan fisik dan kebugaran tubuh", "D. Kecerdasan otak dan logika"]'::jsonb, 'C. Kesehatan fisik dan kebugaran tubuh'),
(5, 'Untuk melatih kebugaran tubuh setiap hari, Baden-Powell menyarankan rutinitas senam pagi yang dikenal sebagai...', '["A. Senam Kesegaran Jasmani (SKJ)", "B. 6 Latihan Fisik BP (BP Exercises)", "C. Senam Pagi Indonesia", "D. Senam Aerobik"]'::jsonb, 'B. 6 Latihan Fisik BP (BP Exercises)'),
(5, 'Cerita Api Unggun ke-18 dan 19 mengulas tentang kebiasaan yang menyehatkan serta pencegahan penyakit. Baden-Powell sangat mewajibkan pandu bernapas dengan benar melalui...', '["A. Hidung, bukan mulut", "B. Mulut secara perlahan", "C. Dada secara dalam", "D. Perut bagian bawah"]'::jsonb, 'A. Hidung, bukan mulut'),
(5, 'Penyakit yang sering menyerang anggota perkemahan akibat meminum air mentah atau lingkungan perkemahan yang kurang bersih (sanitasi buruk) adalah...', '["A. Tifus dan Malaria", "B. Demam Berdarah", "C. Flu dan Batuk", "D. Diare dan Disentri"]'::jsonb, 'D. Diare dan Disentri'),
(5, 'Cerita Api Unggun ke-20 bertemakan "Sikap Kesatria" (Chivalry). Inspirasi utama Baden-Powell dalam membentuk karakter Pramuka ini berasal dari legenda pahlawan kuno, yaitu...', '["A. Kesatria Templar", "B. Kesatria Meja Bundar (Knights of the Round Table)", "C. Pasukan Spartan", "D. Samurai Jepang"]'::jsonb, 'B. Kesatria Meja Bundar (Knights of the Round Table)'),
(5, 'Raja legendaris Inggris yang memimpin para kesatria mulia dalam perumpamaan Baden-Powell tersebut adalah...', '["A. Raja Richard", "B. Raja George", "C. Raja Arthur", "D. Raja Edward"]'::jsonb, 'C. Raja Arthur'),
(5, 'Tokoh orang suci pelindung Inggris (Patron Saint) yang juga dijadikan sebagai pelindung simbolis kaum pandu di seluruh dunia karena keberaniannya membunuh naga adalah...', '["A. Santo George (St. George)", "B. Santo Petrus", "C. Santo Paulus", "D. Santo Andreas"]'::jsonb, 'A. Santo George (St. George)'),
(5, 'Hari peringatan St. George, yang sering dirayakan secara internasional oleh anggota Pramuka sebagai ajang pembaruan Janji Pramuka, jatuh pada tanggal...', '["A. 22 Februari", "B. 23 April", "C. 14 Agustus", "D. 1 Juni"]'::jsonb, 'B. 23 April'),
(5, 'Cerita Api Unggun ke-21 menekankan pada konsep utama watak yang membuat seorang pandu dihormati, yaitu...', '["A. Keberanian", "B. Kecerdasan", "C. Disiplin", "D. Kecekatan"]'::jsonb, 'C. Disiplin'),
(5, 'Ciri sejati dari kedisiplinan seorang Pramuka saat menerima instruksi dari pimpinannya adalah...', '["A. Mematuhi perintah dan aturan dengan sigap tanpa mengeluh", "B. Menanyakan alasan setiap perintah terlebih dahulu", "C. Melaksanakan perintah hanya jika dirasa masuk akal", "D. Mengerjakan perintah dengan pelan agar teliti"]'::jsonb, 'A. Mematuhi perintah dan aturan dengan sigap tanpa mengeluh'),
(5, 'Cerita Api Unggun ke-22 berjudul "Memperbaiki Diri". Hal ini mengajarkan filosofi bahwa seorang pandu sejati harus...', '["A. Sering mengganti seragamnya agar selalu rapi", "B. Mencari kelemahan orang lain untuk diperbaiki", "C. Memperbaiki peralatan perkemahan yang rusak", "D. Terus mengasah keahlian dan akhlaknya secara mandiri agar hidupnya lebih berguna"]'::jsonb, 'D. Terus mengasah keahlian dan akhlaknya secara mandiri agar hidupnya lebih berguna'),
(5, 'Cerita Api Unggun ke-23 dan 24 membahas tentang keterampilan vital yang harus dimiliki setiap Pramuka jika terjadi insiden darurat, yakni tentang...', '["A. Evakuasi Bencana Alam", "B. Menyelamatkan Hidup dan Penanganan Kecelakaan (P3K)", "C. Membuat Pemancar Radio Darurat", "D. Teknik Berenang Jarak Jauh"]'::jsonb, 'B. Menyelamatkan Hidup dan Penanganan Kecelakaan (P3K)'),
(5, 'Kaidah terpenting dan pertama kali yang harus dikuasai secara mental saat seorang Pramuka menghadapi situasi kecelakaan parah adalah...', '["A. Tetap tenang dan tidak panik", "B. Langsung memindahkan korban", "C. Berteriak meminta tolong sekeras mungkin", "D. Mengobati luka dengan obat apa saja"]'::jsonb, 'A. Tetap tenang dan tidak panik'),
(5, 'Apabila menemui korban yang mengalami pendarahan hebat (luka terbuka memancar), tindakan Pertolongan Pertama yang paling efektif dilakukan adalah...', '["A. Memberikan korban air minum yang banyak", "B. Mencuci luka dengan air sungai mengalir", "C. Melakukan tekanan langsung pada area luka / balut tekan", "D. Mengoleskan salep antibiotik di atas luka"]'::jsonb, 'C. Melakukan tekanan langsung pada area luka / balut tekan'),
(5, 'Jika pakaian yang dikenakan oleh seseorang tiba-tiba tersambar api dan terbakar, tindakan penyelematan yang paling tepat diinstruksikan oleh Pramuka adalah...', '["A. Menyuruhnya berlari mencari air", "B. Menyuruhnya berguling-guling di tanah atau membungkusnya rapat dengan selimut tebal", "C. Mengipasi badannya agar api cepat padam", "D. Menyemprotkan cairan alkohol"]'::jsonb, 'B. Menyuruhnya berguling-guling di tanah atau membungkusnya rapat dengan selimut tebal'),
(5, 'Cerita Api Unggun ke-25 mengingatkan tentang tujuan mulia kehadiran gerakan Pramuka dalam masyarakat, yaitu kewajiban untuk...', '["A. Menjaga keamanan desa", "B. Mengatur lalu lintas jalan", "C. Menjadi tentara cadangan", "D. Menolong orang lain di setiap kesempatan"]'::jsonb, 'D. Menolong orang lain di setiap kesempatan'),
(5, 'Sebuah tradisi pandu yang diajarkan oleh Baden-Powell untuk melakukan setidaknya satu kebaikan kecil setiap harinya tanpa mengharap imbalan disebut dengan istilah...', '["A. Good Turn (Berbuat Kebaikan)", "B. Daily Duty (Tugas Harian)", "C. Charity Work (Amal)", "D. Boy Scout Magic"]'::jsonb, 'A. Good Turn (Berbuat Kebaikan)'),
(5, 'Cerita Api Unggun ke-26, yang menjadi bab pamungkas dalam materi buku Scouting for Boys, secara umum membahas tentang sikap tanggung jawab bermasyarakat, yakni...', '["A. Demokrasi (Democracy)", "B. Kewarganegaraan (Citizenship)", "C. Kepemimpinan (Leadership)", "D. Kemandirian (Independence)"]'::jsonb, 'B. Kewarganegaraan (Citizenship)'),
(5, 'Inti dari jiwa kewarganegaraan seorang Pramuka adalah kemauannya untuk memahami sejarah, pemerintahan, dan hukum bangsanya, agar kelak ia menjadi...', '["A. Politikus yang handal", "B. Pekerja yang kaya raya", "C. Warga negara yang aktif dan bermanfaat bagi negaranya", "D. Pejabat militer"]'::jsonb, 'C. Warga negara yang aktif dan bermanfaat bagi negaranya'),
(5, 'Semboyan kepanduan utama yang diperkenalkan Baden-Powell dalam buku ini, yang wajib dipraktikkan baik dalam kesiapan fisik maupun mental oleh pandu di seluruh dunia adalah...', '["A. Be Prepared (Selalu Siap)", "B. Do Your Best (Lakukan yang Terbaik)", "C. Be Brave (Pemberani)", "D. Semper Fidelis (Selalu Setia)"]'::jsonb, 'A. Be Prepared (Selalu Siap)'),
(5, 'Pesan moral secara keseluruhan dari Scouting for Boys yang tercantum di Bab 5 Boyman adalah membentuk remaja agar tidak hanya menjadi sosok petualang alam bebas, tetapi juga menjadi...', '["A. Atlet olahraga yang profesional", "B. Ilmuwan yang ahli flora dan fauna", "C. Prajurit tempur di garis depan", "D. Pria yang bertanggung jawab, mandiri, dan berkarakter mulia"]'::jsonb, 'D. Pria yang bertanggung jawab, mandiri, dan berkarakter mulia');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(9, 'Pengertian berkemah dalam kepramukaan pada dasarnya adalah...', '["A. Pindah rumah sementara ke hutan", "B. Kegiatan hidup di alam bebas dengan menggunakan tenda sebagai tempat berlindung", "C. Latihan fisik militer", "D. Kegiatan rekreasi keluarga"]'::jsonb, 'B. Kegiatan hidup di alam bebas dengan menggunakan tenda sebagai tempat berlindung'),
(9, 'Salah satu sasaran dan motivasi utama dari kegiatan berkemah bagi anggota Pramuka adalah...', '["A. Melatih kemandirian, gotong royong, dan kedisiplinan di alam terbuka", "B. Mencari harta karun", "C. Menghindari tugas sekolah", "D. Berburu hewan liar"]'::jsonb, 'A. Melatih kemandirian, gotong royong, dan kedisiplinan di alam terbuka'),
(9, 'Tahap pertama yang mutlak harus dilakukan sebelum menyelenggarakan kegiatan perkemahan adalah...', '["A. Langsung mendirikan tenda", "B. Menyusun Perencanaan dan Persiapan (surat izin, lokasi, anggaran)", "C. Membeli makanan", "D. Mengumpulkan kayu bakar"]'::jsonb, 'B. Menyusun Perencanaan dan Persiapan (surat izin, lokasi, anggaran)'),
(9, 'Syarat utama tapak kemah (lokasi perkemahan) yang baik dan aman adalah...', '["A. Berada di tengah jalan setapak", "B. Dekat dengan sumber air yang bersih dan aman dari bahaya alam", "C. Di bawah pohon beringin yang rimbun dan tua", "D. Di dasar lembah yang curam"]'::jsonb, 'B. Dekat dengan sumber air yang bersih dan aman dari bahaya alam'),
(9, 'Mengapa mendirikan tenda di dasar cekungan (lembah sempit) sangat dilarang dalam aturan perkemahan?', '["A. Karena pemandangannya kurang bagus", "B. Karena suhu akan terlalu panas", "C. Sangat berbahaya jika terjadi hujan lebat karena rawan banjir bandang/genangan air", "D. Karena sulit mencari kayu bakar"]'::jsonb, 'C. Sangat berbahaya jika terjadi hujan lebat karena rawan banjir bandang/genangan air'),
(9, 'Mendirikan tenda di bawah pohon tua yang sudah lapuk sangat dihindari karena...', '["A. Mengganggu burung", "B. Rawan tertimpa dahan atau pohon tumbang jika ada angin kencang", "C. Banyak nyamuk", "D. Akarnya keras"]'::jsonb, 'B. Rawan tertimpa dahan atau pohon tumbang jika ada angin kencang'),
(9, 'Arah pintu tenda yang ideal saat didirikan di alam bebas sebaiknya...', '["A. Menghadap langsung ke arah hembusan angin utama", "B. Membelakangi atau menyamping dari arah hembusan angin utama", "C. Menghadap ke tebing", "D. Menghadap ke matahari terbenam"]'::jsonb, 'B. Membelakangi atau menyamping dari arah hembusan angin utama'),
(9, 'Tujuan utama membuat parit kecil di sekeliling tenda saat berkemah adalah...', '["A. Menjebak hewan liar", "B. Saluran irigasi", "C. Mencegah air hujan masuk/menggenangi bagian dalam tenda", "D. Pembatas wilayah regu"]'::jsonb, 'C. Mencegah air hujan masuk/menggenangi bagian dalam tenda'),
(9, 'Tenda darurat sementara yang dibuat dari bahan alam atau jas hujan (ponco) dinamakan...', '["A. Bivak", "B. Tenda Dome", "C. Tenda Pleton", "D. Tenda Prisma"]'::jsonb, 'A. Bivak'),
(9, 'Tenda standar beregu yang sering digunakan oleh Pramuka Penggalang, bentuknya seperti rumah dengan atap segitiga disebut...', '["A. Tenda Dome", "B. Tenda Pleton", "C. Tenda Prisma (Tenda Regu)", "D. Tenda Lorong"]'::jsonb, 'C. Tenda Prisma (Tenda Regu)'),
(9, 'Agar patok (pasak) tenda menancap kuat menahan tarikan tali, kemiringan pasak yang ditancapkan ke tanah sebaiknya bersudut...', '["A. 90 derajat lurus ke bawah", "B. Miring 45-60 derajat berlawanan dengan arah tarikan tali tenda", "C. Miring sejajar dengan tali", "D. Dibiarkan tergeletak"]'::jsonb, 'B. Miring 45-60 derajat berlawanan dengan arah tarikan tali tenda'),
(9, 'Simpul yang paling tepat digunakan untuk mengikatkan tali tenda pada pasak agar mudah dikencangkan dan dikendurkan adalah...', '["A. Simpul Pangkal", "B. Simpul Tarik", "C. Simpul Mati", "D. Simpul Tali Tenda (Taut-line Hitch)"]'::jsonb, 'D. Simpul Tali Tenda (Taut-line Hitch)'),
(9, 'Perlengkapan perkemahan dibagi menjadi dua macam, yaitu...', '["A. Perlengkapan Pribadi (Perorangan) dan Perlengkapan Regu (Kelompok)", "B. Perlengkapan Masak dan Perlengkapan Tidur", "C. Perlengkapan Darat dan Air", "D. Perlengkapan Murah dan Mahal"]'::jsonb, 'A. Perlengkapan Pribadi (Perorangan) dan Perlengkapan Regu (Kelompok)'),
(9, 'Berikut ini yang termasuk ke dalam Perlengkapan Pribadi saat berkemah adalah...', '["A. Tenda, kompor, dan panci", "B. Pakaian ganti, sleeping bag, alat mandi, dan obat pribadi", "C. Bendera regu dan kapak", "D. Lentera dan jerigen air"]'::jsonb, 'B. Pakaian ganti, sleeping bag, alat mandi, dan obat pribadi'),
(9, 'Berikut ini yang termasuk ke dalam Perlengkapan Regu adalah...', '["A. Sepatu lapangan dan kaus kaki", "B. Sikat gigi dan sabun", "C. Tenda, alat masak regu (nesting), dan kotak P3K regu", "D. Jaket dan jas hujan"]'::jsonb, 'C. Tenda, alat masak regu (nesting), dan kotak P3K regu'),
(9, 'Alat pelindung tubuh dari suhu dingin saat tidur di dalam tenda yang bentuknya seperti kepompong disebut...', '["A. Matras", "B. Sleeping Bag (Kantong Tidur)", "C. Jas Hujan", "D. Hammock"]'::jsonb, 'B. Sleeping Bag (Kantong Tidur)'),
(9, 'Alat berupa alas tidur berbahan busa/spons yang berfungsi menahan hawa dingin dari tanah agar tidak langsung mengenai tubuh disebut...', '["A. Sleeping Bag", "B. Matras", "C. Ponco", "D. Tenda"]'::jsonb, 'B. Matras'),
(9, 'Tas besar khusus untuk membawa perlengkapan berkemah yang bentuknya dirancang mengikuti anatomi punggung disebut...', '["A. Tas selempang", "B. Koper", "C. Ransel (Carrier / Backpack)", "D. Tas jinjing"]'::jsonb, 'C. Ransel (Carrier / Backpack)'),
(9, 'Prinsip dasar saat melakukan "Packing" (mengepak barang ke dalam ransel) agar tidak membuat punggung cepat lelah adalah...', '["A. Barang berat ditaruh paling bawah", "B. Barang berat ditaruh di atas, barang ringan di bawah dan menempel punggung", "C. Semua barang dicampur aduk", "D. Barang berat ditaruh di luar tas"]'::jsonb, 'B. Barang berat ditaruh di atas, barang ringan di bawah dan menempel punggung'),
(9, 'Selain masalah berat, prinsip "Packing" yang baik untuk melindungi barang dari hujan adalah...', '["A. Menggunakan payung di atas tas", "B. Melapisi bagian dalam ransel dengan kantong plastik sampah (Trash Bag) besar sebelum diisi barang", "C. Menjemur tas di panas matahari", "D. Membawa tas di depan dada"]'::jsonb, 'B. Melapisi bagian dalam ransel dengan kantong plastik sampah (Trash Bag) besar sebelum diisi barang'),
(9, 'Jas hujan berukuran besar berbentuk kelelawar yang dapat dialihfungsikan sebagai atap bivak darurat dinamakan...', '["A. Jas Hujan Setelan", "B. Mantel", "C. Ponco", "D. Payung"]'::jsonb, 'C. Ponco'),
(9, 'Syarat bahan makanan yang ideal untuk dibawa saat perkemahan adalah...', '["A. Berat, mahal, dan mudah basi", "B. Praktis, awet/tahan lama, bernilai gizi tinggi, dan mudah dimasak", "C. Cepat saji namun tidak bergizi", "D. Makanan berkuah dalam plastik"]'::jsonb, 'B. Praktis, awet/tahan lama, bernilai gizi tinggi, dan mudah dimasak'),
(9, 'Alat masak portabel berbahan aluminium yang sering digunakan oleh militer dan pramuka karena bisa disusun menjadi satu wadah ringkas disebut...', '["A. Wajan", "B. Panci Presto", "C. Nesting", "D. Dandang"]'::jsonb, 'C. Nesting'),
(9, 'Lokasi yang TEPAT untuk menyalakan perapian atau kompor saat berkemah adalah...', '["A. Di dalam tenda agar hangat", "B. Di teras tenda dekat bahan kain", "C. Di luar tenda pada tempat terbuka dan aman dari tiupan angin kencang atau dedaunan kering", "D. Di bawah pohon yang rindang"]'::jsonb, 'C. Di luar tenda pada tempat terbuka dan aman dari tiupan angin kencang atau dedaunan kering'),
(9, 'Hal yang mutlak DILARANG dilakukan di dalam tenda karena sangat berbahaya adalah...', '["A. Menyalakan api, kompor, lentera minyak, atau lilin", "B. Mengobrol", "C. Tidur menggunakan sleeping bag", "D. Menyimpan pakaian kotor"]'::jsonb, 'A. Menyalakan api, kompor, lentera minyak, atau lilin'),
(9, 'Pembuatan fasilitas MCK (Mandi Cuci Kakus) darurat di area kemah harus berjarak minimal...', '["A. 1 meter dari tenda", "B. 5 meter dari sumber air dan tenda", "C. 15-20 meter dari sumber air agar tidak mencemari mata air", "D. Bebas di mana saja"]'::jsonb, 'C. 15-20 meter dari sumber air agar tidak mencemari mata air'),
(9, 'Manajemen sampah di area perkemahan untuk jenis sampah anorganik (plastik, kaleng, kaca) yang paling benar adalah...', '["A. Dibakar sampai habis", "B. Dikubur di dalam tanah", "C. Dibuang ke sungai", "D. Dikumpulkan dalam kantong sampah lalu dibawa turun/pulang (Pack it in, Pack it out)"]'::jsonb, 'D. Dikumpulkan dalam kantong sampah lalu dibawa turun/pulang (Pack it in, Pack it out)'),
(9, 'Sampah organik (sisa makanan) di area perkemahan sebaiknya...', '["A. Dibuang sembarangan", "B. Dikubur dalam lubang kecil yang tertutup rapat agak jauh dari tenda agar tidak mengundang hewan", "C. Ditinggalkan di atas meja", "D. Dibuang ke tenda regu lain"]'::jsonb, 'B. Dikubur dalam lubang kecil yang tertutup rapat agak jauh dari tenda agar tidak mengundang hewan'),
(9, 'Saat mengambil air minum dari sungai atau mata air alam, langkah wajib yang harus dilakukan sebelum meminumnya adalah...', '["A. Diminum langsung jika terlihat jernih", "B. Disaring dengan kain lalu direbus hingga mendidih (matang) untuk membunuh bakteri", "C. Didinginkan", "D. Diendapkan 1 jam"]'::jsonb, 'B. Disaring dengan kain lalu direbus hingga mendidih (matang) untuk membunuh bakteri'),
(9, 'Api unggun dalam kegiatan perkemahan memiliki fungsi utama sebagai...', '["A. Ajang membakar sampah", "B. Sarana persaudaraan, kehangatan, dan pertunjukan seni", "C. Mengusir regu lain", "D. Alat penerangan untuk membaca buku"]'::jsonb, 'B. Sarana persaudaraan, kehangatan, dan pertunjukan seni'),
(9, 'Aturan utama dalam membuat api unggun di alam bebas agar tidak merusak lingkungan adalah...', '["A. Dibuat langsung di atas rumput hijau", "B. Dibuat sebesar mungkin", "C. Membuat alas perapian (dari tanah/batu) atau tidak merusak area vegetasi di bawahnya", "D. Menggunakan kayu hidup"]'::jsonb, 'C. Membuat alas perapian (dari tanah/batu) atau tidak merusak area vegetasi di bawahnya'),
(9, 'Pakaian lapangan yang ideal untuk berkemah adalah...', '["A. Celana jeans ketat dan kaos tipis", "B. Pakaian berbahan katun/ripstop yang menyerap keringat, kuat, dan cepat kering (PDL)", "C. Celana bahan sutra", "D. Celana pendek pantai"]'::jsonb, 'B. Pakaian berbahan katun/ripstop yang menyerap keringat, kuat, dan cepat kering (PDL)'),
(9, 'Mengapa celana berbahan Jeans/Denim SANGAT TIDAK disarankan dipakai untuk kegiatan kemah di alam bebas?', '["A. Harganya mahal", "B. Berat, tidak menyerap keringat, susah bergerak, dan sangat lama kering jika basah (bisa memicu hipotermia)", "C. Terlalu tebal sehingga panas", "D. Warnanya mudah pudar"]'::jsonb, 'B. Berat, tidak menyerap keringat, susah bergerak, dan sangat lama kering jika basah (bisa memicu hipotermia)'),
(9, 'Jenis alas kaki yang paling aman untuk kegiatan perkemahan dan penjelajahan adalah...', '["A. Sandal jepit", "B. Sepatu pantofel", "C. Sepatu lapangan/gunung yang menutupi mata kaki (Boot/Trekking Shoes)", "D. Sepatu roda"]'::jsonb, 'C. Sepatu lapangan/gunung yang menutupi mata kaki (Boot/Trekking Shoes)'),
(9, 'Lembaran kain sintetis kedap air yang sering dipasang di atas tenda untuk menahan air hujan atau dibuat sebagai atap teras dinamakan...', '["A. Flysheet", "B. Groundsheet", "C. Hammock", "D. Matras"]'::jsonb, 'A. Flysheet'),
(9, 'Alat kedap air yang diletakkan di bawah (lantai dasar) tenda agar uap air dari tanah tidak tembus ke dalam dinamakan...', '["A. Flysheet", "B. Groundsheet / Terpal", "C. Matras", "D. Ponco"]'::jsonb, 'B. Groundsheet / Terpal'),
(9, 'Aturan keamanan saat memegang dan berjalan membawa senjata tajam (golok/pisau) di perkemahan adalah...', '["A. Diayun-ayunkan sambil berjalan", "B. Diselipkan di dada", "C. Memegang bagian gagang dengan sisi tajam menghadap ke belakang/bawah, atau dimasukkan ke dalam sarungnya", "D. Dilempar ke teman"]'::jsonb, 'C. Memegang bagian gagang dengan sisi tajam menghadap ke belakang/bawah, atau dimasukkan ke dalam sarungnya'),
(9, 'Saat ada anggota yang bertugas piket jaga malam, posisi jaga yang paling benar adalah...', '["A. Tidur di teras tenda", "B. Berjaga secara bergantian dan tidak jauh dari api/sumber cahaya darurat", "C. Meninggalkan area kemah sendirian", "D. Mengobrol keras-keras"]'::jsonb, 'B. Berjaga secara bergantian dan tidak jauh dari api/sumber cahaya darurat'),
(9, 'Jika tenda bocor parah di tengah hujan badai malam hari dan seluruh pakaian basah kuyup, ancaman kesehatan paling berbahaya adalah...', '["A. Dehidrasi", "B. Hipotermia", "C. Malaria", "D. Asma"]'::jsonb, 'B. Hipotermia'),
(9, 'Etika perkemahan saat malam hari (Quiet Hours) mengharuskan seluruh anggota untuk...', '["A. Menghentikan aktivitas berisik dan beristirahat agar tidak mengganggu makhluk hidup dan tenda lain", "B. Menyalakan musik keras-keras", "C. Tetap berlatih baris-berbaris", "D. Menebang pohon"]'::jsonb, 'A. Menghentikan aktivitas berisik dan beristirahat agar tidak mengganggu makhluk hidup dan tenda lain'),
(9, 'Langkah pertama saat akan membongkar tenda di akhir kegiatan kemah adalah...', '["A. Langsung mencabut semua pasak", "B. Mengeluarkan dan membersihkan seluruh barang dari dalam tenda", "C. Melipat tenda", "D. Mematahkan tongkat"]'::jsonb, 'B. Mengeluarkan dan membersihkan seluruh barang dari dalam tenda'),
(9, 'Syarat utama sebelum melipat kain tenda untuk disimpan ke dalam tas adalah...', '["A. Tenda harus dicuci sabun terlebih dahulu", "B. Tenda dibiarkan basah", "C. Tenda harus dalam keadaan benar-benar kering agar tidak berjamur", "D. Tenda harus disetrika"]'::jsonb, 'C. Tenda harus dalam keadaan benar-benar kering agar tidak berjamur'),
(9, 'Prinsip pencinta alam "Leave No Trace" (Jangan tinggalkan jejak) mengajarkan kita untuk...', '["A. Tidak boleh berjalan di tanah", "B. Mengambil apapun yang terlihat bagus di hutan", "C. Membiarkan kondisi tapak kemah sama bersihnya atau lebih bersih daripada saat kita baru datang", "D. Menghapus jejak kaki dengan sapu"]'::jsonb, 'C. Membiarkan kondisi tapak kemah sama bersihnya atau lebih bersih daripada saat kita baru datang'),
(9, 'Kotak atau tas darurat berukuran kecil berisi perlengkapan bertahan hidup esensial (seperti korek anti air, kail pancing, pisau lipat, plester) dinamakan...', '["A. First Aid Kit", "B. Survival Kit", "C. Nesting", "D. Carrier"]'::jsonb, 'B. Survival Kit'),
(9, 'Tindakan yang benar jika tersesat saat melakukan kegiatan penjelajahan di sekitar perkemahan adalah...', '["A. Berlari secepat mungkin tanpa arah", "B. STOP (Stop, Think, Observe, Plan) dan tidak panik", "C. Membuang semua barang bawaan", "D. Bersembunyi dari tim SAR"]'::jsonb, 'B. STOP (Stop, Think, Observe, Plan) dan tidak panik'),
(9, 'Fungsi menggunakan pakaian lengan panjang saat menerobos semak/hutan di area kemah adalah...', '["A. Agar terlihat rapi", "B. Menahan dingin, melindungi dari duri, goresan ranting, dan gigitan serangga", "C. Menghindari sinar bulan", "D. Syarat wajib topi rimba"]'::jsonb, 'B. Menahan dingin, melindungi dari duri, goresan ranting, dan gigitan serangga'),
(9, 'Tanda yang dibuat oleh anggota Pramuka menggunakan batu, ranting, atau goresan tanah untuk memberi petunjuk arah di alam bebas disebut...', '["A. Sandi Morse", "B. Tanda Jejak", "C. Peta Pita", "D. Simpul"]'::jsonb, 'B. Tanda Jejak'),
(9, 'Sikap mental yang paling dituntut dari seorang pemimpin regu saat perkemahan dilanda cuaca buruk adalah...', '["A. Marah-marah", "B. Ikut panik bersama anggotanya", "C. Tenang, mengambil keputusan cepat untuk mengamankan anggota, dan menjaga moral regu", "D. Menyalahkan panitia"]'::jsonb, 'C. Tenang, mengambil keputusan cepat untuk mengamankan anggota, dan menjaga moral regu'),
(9, 'Obat yang wajib dibawa secara pribadi (tidak boleh mengandalkan regu) saat berkemah adalah...', '["A. Betadine", "B. Obat penyakit khusus/alergi yang diidap oleh diri sendiri", "C. Paracetamol", "D. Obat nyamuk"]'::jsonb, 'B. Obat penyakit khusus/alergi yang diidap oleh diri sendiri'),
(9, 'Tujuan akhir setelah kembali dari kegiatan berkemah adalah...', '["A. Langsung membuang peralatan", "B. Melakukan evaluasi kegiatan, membersihkan dan merawat kembali peralatan agar siap dipakai di kemudian hari", "C. Mengadakan pesta", "D. Lupa pada pelajaran yang didapat"]'::jsonb, 'B. Melakukan evaluasi kegiatan, membersihkan dan merawat kembali peralatan agar siap dipakai di kemudian hari');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(12, 'Kata "Sandi" berasal dari bahasa Sanskerta, yang memiliki arti...', '["A. Tanda", "B. Rahasia", "C. Tulisan", "D. Isyarat"]'::jsonb, 'B. Rahasia'),
(12, 'Fungsi utama mempelajari sandi dalam kegiatan kepramukaan adalah untuk...', '["A. Menarik perhatian orang tua", "B. Melatih daya ingat, kecerdasan, dan ketelitian", "C. Menyembunyikan barang bawaan", "D. Syarat wajib berkemah"]'::jsonb, 'B. Melatih daya ingat, kecerdasan, dan ketelitian'),
(12, 'Penemu sistem telegraf dan kode Morse adalah seorang seniman dan penemu asal Amerika yang bernama...', '["A. Robert Baden-Powell", "B. Samuel F.B. Morse", "C. Alexander Graham Bell", "D. Thomas Alva Edison"]'::jsonb, 'B. Samuel F.B. Morse'),
(12, 'Kode Morse pertama kali ditemukan dan digunakan secara praktis pada tahun...', '["A. 1837", "B. 1850", "C. 1908", "D. 1912"]'::jsonb, 'A. 1837'),
(12, 'Dalam standar internasional, perbandingan durasi waktu antara bunyi/simbol "titik" dan "garis" pada sandi Morse adalah...', '["A. 1 : 2", "B. 1 : 3", "C. 2 : 3", "D. 1 : 4"]'::jsonb, 'B. 1 : 3'),
(12, 'Huruf yang direpresentasikan dengan satu titik (.) dalam sandi Morse adalah...', '["A. A", "B. E", "C. I", "D. T"]'::jsonb, 'B. E'),
(12, 'Huruf yang direpresentasikan dengan satu garis (-) dalam sandi Morse adalah...', '["A. M", "B. N", "C. T", "D. O"]'::jsonb, 'C. T'),
(12, 'Kode Morse untuk huruf "A" adalah...', '["A. .-", "B. -.", "C. ..", "D. --"]'::jsonb, 'A. .-'),
(12, 'Kode Morse untuk huruf "B" adalah...', '["A. -...", "B. -.-.", "C. -..", "D. -.-"]'::jsonb, 'A. -...'),
(12, 'Sinyal marabahaya darurat atau minta tolong standar internasional (SOS) dalam sandi Morse ditulis dengan...', '["A. --- ... ---", "B. ... --- ...", "C. ... ... ...", "D. --- --- ---"]'::jsonb, 'B. ... --- ...'),
(12, 'Kode Morse (...--) melambangkan angka...', '["A. 1", "B. 2", "C. 3", "D. 4"]'::jsonb, 'C. 3'),
(12, 'Kode Morse (---..) melambangkan angka...', '["A. 6", "B. 7", "C. 8", "D. 9"]'::jsonb, 'C. 8'),
(12, 'Kode Morse (----.) melambangkan angka...', '["A. 7", "B. 8", "C. 9", "D. 0"]'::jsonb, 'C. 9'),
(12, 'Tanda pemisah antar kata saat menulis sandi Morse di atas kertas biasanya menggunakan tanda...', '["A. Titik dua (:)", "B. Garis miring ganda (//)", "C. Tanda hubung (-)", "D. Garis bawah (_)"]'::jsonb, 'B. Garis miring ganda (//)'),
(12, 'Dalam pengiriman pesan Morse, tanda untuk memulai panggilan atau "Attention" biasanya menggunakan kode...', '["A. -.-.-.", "B. .-...-", "C. -.-.", "D. ...-.-"]'::jsonb, 'A. -.-.-.'),
(12, 'Isyarat "Pesan Selesai" (End of Message) dalam pengiriman Morse ditandai dengan kode gabungan huruf AR, yaitu...', '["A. .-.-.", "B. ...-.-", "C. -...-", "D. .-..."]'::jsonb, 'A. .-.-.'),
(12, 'Jika pengirim melakukan kesalahan saat mengirim sandi Morse, ia memberikan isyarat salah (E 8 kali) yang berbunyi...', '["A. --------", "B. ........", "C. .-.-.-.-", "D. -.-.-.-."]'::jsonb, 'B. ........'),
(20, 'Sandi yang menggunakan bentuk garis vertikal, horizontal, dan titik sebagai pengganti huruf disebut...', '["A. Sandi Rumput", "B. Sandi Kotak", "C. Sandi Angka", "D. Sandi Kimia"]'::jsonb, 'B. Sandi Kotak'),
(20, 'Sandi Kotak 1 terdiri dari dua macam bentuk pola kerangka, yaitu...', '["A. Garis lurus dan garis miring", "B. Palang tegak lurus dan silang (X)", "C. Lingkaran dan segitiga", "D. Persegi panjang dan jajar genjang"]'::jsonb, 'B. Palang tegak lurus dan silang (X)'),
(20, 'Dalam Sandi Kotak 1, masing-masing kotak pada kerangka palang maksimal diisi oleh...', '["A. 1 huruf", "B. 2 huruf", "C. 3 huruf", "D. 4 huruf"]'::jsonb, 'B. 2 huruf'),
(20, 'Dalam Sandi Kotak 1, huruf "B" digambarkan dengan bentuk sudut siku-siku terbuka ke atas-kanan, ditambah dengan...', '["A. Tanpa titik", "B. 1 titik", "C. 2 titik", "D. 3 titik"]'::jsonb, 'B. 1 titik'),
(20, 'Dalam Sandi Kotak 1, huruf "A" digambarkan dengan bentuk sudut siku-siku terbuka ke atas-kanan, ditambah dengan...', '["A. Tanpa titik", "B. 1 titik", "C. 2 titik", "D. Garis miring"]'::jsonb, 'A. Tanpa titik'),
(20, 'Perbedaan utama antara Sandi Kotak 1 dan Sandi Kotak 2 (versi Boyman) terletak pada...', '["A. Bentuk silangnya dihilangkan", "B. Setiap kotak berisi 3 huruf dan menggunakan maksimal 2 titik", "C. Huruf A sampai Z dibuat dalam satu baris", "D. Menggunakan angka sebagai pengganti titik"]'::jsonb, 'B. Setiap kotak berisi 3 huruf dan menggunakan maksimal 2 titik'),
(20, 'Dalam Sandi Kotak 2, huruf "C" ditandai dengan kotak yang sama dengan A dan B, namun menggunakan...', '["A. Tidak menggunakan titik", "B. Menggunakan 1 titik", "C. Menggunakan 2 titik", "D. Menggunakan 3 titik"]'::jsonb, 'C. Menggunakan 2 titik'),
(20, 'Sandi Kotak 3 memiliki bentuk dasar kerangka yang unik, yaitu susunan dari...', '["A. Segitiga dan lingkaran", "B. Belah ketupat (segi empat silang)", "C. Persegi panjang memanjang", "D. Garis-garis sejajar"]'::jsonb, 'B. Belah ketupat (segi empat silang)'),
(20, 'Sandi Rumput merupakan bentuk aplikasi visual lain dari...', '["A. Sandi Kotak", "B. Sandi Angka", "C. Sandi Morse", "D. Semaphore"]'::jsonb, 'C. Sandi Morse'),
(20, 'Pada Sandi Rumput, lambang titik (.) pada morse digambarkan dengan...', '["A. Rumput tinggi", "B. Rumput pendek", "C. Gundukan tanah", "D. Bunga"]'::jsonb, 'B. Rumput pendek'),
(20, 'Pada Sandi Rumput, lambang garis (-) pada morse digambarkan dengan...', '["A. Rumput tinggi", "B. Rumput pendek", "C. Pohon", "D. Batu"]'::jsonb, 'A. Rumput tinggi'),
(20, 'Sandi yang mengubah urutan abjad sedemikian rupa sehingga huruf "A" dibaca sebagai "N", "B" dibaca "O", dan seterusnya, disebut...', '["A. Sandi AZ", "B. Sandi AN", "C. Sandi Koordinat", "D. Sandi Geser"]'::jsonb, 'B. Sandi AN'),
(20, 'Kata "PRAMUKA" jika dipecahkan menggunakan Sandi AN akan berbunyi...', '["A. CENZHXN", "B. CENZHYA", "C. CENZHKN", "D. CRAMHXA"]'::jsonb, 'A. CENZHXN'),
(20, 'Sandi yang menukar huruf awal alfabet dengan huruf akhir (A=Z, B=Y, C=X) disebut...', '["A. Sandi AZ / Sandi Balik Abjad", "B. Sandi AN", "C. Sandi Cermin", "D. Sandi Rumput"]'::jsonb, 'A. Sandi AZ / Sandi Balik Abjad'),
(20, 'Dalam Sandi Angka dasar, di mana A=1, B=2, dst., maka susunan kode 16-18-1-13-21-11-1 dibaca...', '["A. PENGGALANG", "B. PANDU", "C. PRAMUKA", "D. PEMBINA"]'::jsonb, 'C. PRAMUKA'),
(20, 'Sandi Angka juga bisa divariasikan dengan awalan berbeda, misalnya A=0. Jika A=0, maka huruf C adalah angka...', '["A. 0", "B. 1", "C. 2", "D. 3"]'::jsonb, 'C. 2'),
(20, 'Sandi yang pengerjaannya menggunakan dua kata kunci yang digabungkan membentuk tabel baris dan kolom (koordinat), dan total huruf kuncinya berjumlah 10 tanpa pengulangan, disebut...', '["A. Sandi Angka", "B. Sandi Koordinat", "C. Sandi Jam", "D. Sandi Kimia"]'::jsonb, 'B. Sandi Koordinat'),
(20, 'Dua kata yang paling sering dijadikan kata kunci dalam Sandi Koordinat Pramuka adalah...', '["A. MERAH PUTIH", "B. PANDU DUNIA", "C. TUNAS KELAPA", "D. GARUDA JAYA"]'::jsonb, 'A. MERAH PUTIH'),
(20, 'Dalam Sandi Koordinat "MERAH PUTIH", huruf "M" mewakili...', '["A. Kolom pertama", "B. Baris pertama", "C. Angka nol", "D. Tanda spasi"]'::jsonb, 'B. Baris pertama'),
(20, 'Sandi yang memanfaatkan patokan interval waktu tertentu sebagai urutan abjad disebut...', '["A. Sandi Waktu", "B. Sandi Menit", "C. Sandi Jam", "D. Sandi Detik"]'::jsonb, 'C. Sandi Jam'),
(20, 'Pada Sandi Jam, jika ditentukan jam 08.00 adalah huruf A, dan interval beda waktu adalah 5 menit, maka huruf B ditulis dengan...', '["A. 08.01", "B. 08.05", "C. 08.10", "D. 08.15"]'::jsonb, 'B. 08.05'),
(20, 'Jika 07.00 = A dengan interval 5 menit, jam berapakah yang menunjukkan huruf C?', '["A. 07.05", "B. 07.10", "C. 07.15", "D. 07.20"]'::jsonb, 'B. 07.10'),
(20, 'Sandi yang mengadopsi cara penulisan unsur kimiawi, dan sebenarnya merupakan kamuflase dari sandi Morse, disebut...', '["A. Sandi Biologi", "B. Sandi Fisika", "C. Sandi Kimia", "D. Sandi Molekul"]'::jsonb, 'C. Sandi Kimia'),
(20, 'Dalam rumus Sandi Kimia Pramuka, huruf Vokal (A, I, U, E, O) berfungsi menggantikan posisi...', '["A. Tanda Titik (.) pada Morse", "B. Tanda Garis (-) pada Morse", "C. Tanda Spasi", "D. Huruf mati"]'::jsonb, 'A. Tanda Titik (.) pada Morse'),
(20, 'Dalam Sandi Kimia, huruf Konsonan (B, C, D, F, dst) berfungsi menggantikan posisi...', '["A. Tanda Titik (.) pada Morse", "B. Tanda Garis (-) pada Morse", "C. Tanda Spasi", "D. Angka"]'::jsonb, 'B. Tanda Garis (-) pada Morse'),
(20, 'Kode Morse ".-" (Huruf A) jika diubah ke dalam Sandi Kimia bisa ditulis menjadi kombinasi Vokal-Konsonan seperti...', '["A. OH", "B. O2", "C. H2O", "D. CO2"]'::jsonb, 'A. OH'),
(20, 'Kata yang disembunyikan dengan menyisipkan kata "AND" di antara setiap hurufnya disebut Sandi AND. Jika tertulis "PAND R AND A M AND U K AND A", kata aslinya adalah...', '["A. PANDU", "B. PRAJA", "C. PRAMUKA", "D. PENGGALANG"]'::jsonb, 'C. PRAMUKA'),
(20, 'Sandi yang bentuknya menyerupai lekukan garis-garis bergelombang, di mana lekukan kecil adalah titik dan lekukan besar adalah garis, dinamakan...', '["A. Sandi Sungai", "B. Sandi Akar", "C. Sandi Arab", "D. Sandi Ular / Sandi Gergaji"]'::jsonb, 'D. Sandi Ular / Sandi Gergaji'),
(20, 'Sandi yang cara membacanya sama dengan cara membaca tulisan Arab, yaitu dari kanan ke kiri, disebut...', '["A. Sandi Balik Kata", "B. Sandi Cermin", "C. Sandi Arab", "D. Sandi Mesir"]'::jsonb, 'C. Sandi Arab'),
(20, 'Kata "AKUMARP" jika dipecahkan menggunakan kaidah Sandi Arab atau Sandi Balik akan berbunyi...', '["A. PRAMUKA", "B. GARUDA", "C. PANDU", "D. SIAGA"]'::jsonb, 'A. PRAMUKA'),
(20, 'Selain menggunakan peluit dan kertas, sandi Morse di malam hari sangat efektif dikirimkan menggunakan media...', '["A. Bendera", "B. Senter / Cahaya", "C. Asap", "D. Ketukan batu"]'::jsonb, 'B. Senter / Cahaya'),
(20, 'Pengiriman isyarat komunikasi tradisional menggunakan kepulan asap sering dikaitkan dengan suku Indian, namun dalam Pramuka juga diajarkan sebagai bagian dari...', '["A. Sandi Asap", "B. Sandi Udara", "C. Sandi Api", "D. Sandi Darurat"]'::jsonb, 'A. Sandi Asap'),
(20, 'Sandi yang menggunakan titik-titik timbul untuk membantu penyandang tunanetra membaca, dan sering masuk dalam materi wawasan komunikasi pandu, diciptakan oleh...', '["A. Louis Braille", "B. Samuel Morse", "C. Lord Baden-Powell", "D. Claude Chappe"]'::jsonb, 'A. Louis Braille');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(15, 'Gambar seluruh atau sebagian permukaan bumi yang diproyeksikan pada bidang datar dengan perbandingan skala tertentu disebut...', '["A. Sketsa", "B. Peta", "C. Maket", "D. Denah"]'::jsonb, 'B. Peta'),
(15, 'Jenis peta yang sangat penting bagi Pramuka karena menggambarkan tinggi rendahnya permukaan bumi (relief) secara detail adalah...', '["A. Peta Tematik", "B. Peta Topografi", "C. Peta Demografi", "D. Peta Politik"]'::jsonb, 'B. Peta Topografi'),
(15, 'Kumpulan penjelasan tentang arti simbol-simbol dan warna yang terdapat pada peta disebut...', '["A. Indeks Peta", "B. Judul Peta", "C. Skala Peta", "D. Legenda Peta"]'::jsonb, 'D. Legenda Peta'),
(15, 'Angka yang menunjukkan perbandingan antara jarak di atas peta dengan jarak sebenarnya di lapangan disebut...', '["A. Koordinat", "B. Elevasi", "C. Skala", "D. Azimuth"]'::jsonb, 'C. Skala'),
(15, 'Peta dengan skala 1 : 25.000 berarti 1 cm pada peta mewakili jarak sebenarnya di lapangan sejauh...', '["A. 25 meter", "B. 250 meter", "C. 2.500 meter", "D. 25.000 meter (25 km)"]'::jsonb, 'B. 250 meter'),
(15, 'Jika jarak antara titik A dan B di peta topografi (skala 1:50.000) adalah 4 cm, maka jarak sebenarnya di lapangan adalah...', '["A. 200 meter", "B. 2 kilometer", "C. 4 kilometer", "D. 20 kilometer"]'::jsonb, 'B. 2 kilometer'),
(15, 'Skala peta yang ditunjukkan dalam bentuk garis lurus yang terbagi menjadi beberapa ruas dengan ukuran satuan jarak tertentu disebut...', '["A. Skala Angka (Numerik)", "B. Skala Verbal", "C. Skala Garis (Grafis)", "D. Skala Pecahan"]'::jsonb, 'C. Skala Garis (Grafis)'),
(15, 'Garis khayal melingkar pada peta topografi yang menghubungkan titik-titik dengan ketinggian yang sama dari permukaan laut disebut...', '["A. Garis Lintang", "B. Garis Bujur", "C. Garis Kontur", "D. Garis Batas"]'::jsonb, 'C. Garis Kontur'),
(15, 'Ciri khas utama dari garis kontur adalah jika jarak antar garisnya tergambar sangat rapat, hal itu menunjukkan bentuk medan yang...', '["A. Datar / Landai", "B. Curam / Terjal", "C. Berbatu", "D. Berawa"]'::jsonb, 'B. Curam / Terjal'),
(15, 'Jika jarak antar garis kontur di peta terlihat renggang atau saling berjauhan, itu menandakan bentuk medan yang...', '["A. Curam", "B. Puncak Gunung", "C. Landai / Datar", "D. Jurang"]'::jsonb, 'C. Landai / Datar'),
(15, 'Garis kontur yang membentuk pola huruf "V" atau "U" terbalik yang menjorok ke arah ketinggian (menunjuk ke tempat yang lebih tinggi) menandakan bentang alam berupa...', '["A. Punggungan bukit", "B. Lembah / Aliran Sungai", "C. Puncak gunung", "D. Kawah"]'::jsonb, 'B. Lembah / Aliran Sungai'),
(15, 'Garis kontur yang membentuk pola huruf "V" atau "U" yang menjorok ke arah tempat yang lebih rendah menandakan bentang alam berupa...', '["A. Lembah", "B. Punggungan (Sadel) / Punggung Bukit", "C. Danau", "D. Pantai"]'::jsonb, 'B. Punggungan (Sadel) / Punggung Bukit'),
(15, 'Garis kontur yang tergambar berupa lingkaran-lingkaran kecil konsentris yang semakin mengecil di bagian tengah biasanya menandakan...', '["A. Puncak bukit / Gunung", "B. Sumur", "C. Danau", "D. Jalan raya"]'::jsonb, 'A. Puncak bukit / Gunung'),
(15, 'Jika ada garis kontur melingkar namun memiliki garis-garis rambut kecil (tick marks) yang mengarah ke bagian dalam lingkaran, itu menandakan...', '["A. Puncak gunung", "B. Hutan lebat", "C. Depresi / Kawah / Cekungan", "D. Pulau"]'::jsonb, 'C. Depresi / Kawah / Cekungan'),
(15, 'Selisih ketinggian atau jarak vertikal antara satu garis kontur dengan garis kontur di sebelahnya disebut...', '["A. Indeks Kontur", "B. Interval Kontur", "C. Titik Triangulasi", "D. Elevasi Maksimum"]'::jsonb, 'B. Interval Kontur'),
(15, 'Garis kontur yang biasanya dicetak lebih tebal dan disertai angka penunjuk ketinggian untuk mempermudah pembacaan peta disebut...', '["A. Kontur Biasa", "B. Kontur Bantuan", "C. Indeks Kontur", "D. Interval Kontur"]'::jsonb, 'C. Indeks Kontur'),
(15, 'Sistem garis kisi-kisi (grid) yang membagi peta menjadi kotak-kotak untuk menentukan posisi secara akurat dinamakan koordinat...', '["A. Astronomis", "B. Geografis", "C. UTM (Universal Transverse Mercator)", "D. Polar"]'::jsonb, 'C. UTM (Universal Transverse Mercator)'),
(15, 'Garis vertikal (membujur dari bawah ke atas) pada sistem koordinat kotak (grid) peta yang angkanya dibaca pertama kali (dibaca ke arah Timur) disebut...', '["A. Northing", "B. Easting", "C. Lintang", "D. Bujur"]'::jsonb, 'B. Easting'),
(15, 'Garis horizontal (melintang dari kiri ke kanan) pada sistem koordinat grid peta yang angkanya dibaca kedua (dibaca ke arah Utara) disebut...', '["A. Easting", "B. Northing", "C. Latitude", "D. Meridian"]'::jsonb, 'B. Northing'),
(15, 'Aturan emas (golden rule) dalam membaca koordinat grid di atas peta topografi adalah...', '["A. Baca yang vertikal dulu, lalu turun", "B. Baca ke atas dulu (Northing), baru ke samping (Easting)", "C. Baca dari kiri ke kanan (Easting), lalu dari bawah ke atas (Northing)", "D. Baca garis miring"]'::jsonb, 'C. Baca dari kiri ke kanan (Easting), lalu dari bawah ke atas (Northing)'),
(15, 'Jika kita diminta menunjuk titik dengan koordinat 6 digit (contoh: 456 789), ini berarti tingkat ketelitian pencarian lokasi tersebut mencapai area seluas...', '["A. 1 km persegi", "B. 100 meter persegi", "C. 10 meter persegi", "D. 1 meter persegi"]'::jsonb, 'B. 100 meter persegi'),
(15, 'Arah Utara yang ditunjukkan oleh garis-garis grid vertikal lurus ke atas pada peta disebut...', '["A. Utara Sebenarnya (True North)", "B. Utara Magnetis (Magnetic North)", "C. Utara Peta (Grid North)", "D. Utara Kutub"]'::jsonb, 'C. Utara Peta (Grid North)'),
(15, 'Arah Utara yang mengarah tepat ke Kutub Utara bumi (poros rotasi) disebut...', '["A. Utara Peta (Grid North)", "B. Utara Magnetis (Magnetic North)", "C. Utara Sebenarnya (True North)", "D. Utara Geografis"]'::jsonb, 'C. Utara Sebenarnya (True North)'),
(15, 'Dalam legenda peta topografi standar, warna COKLAT umumnya digunakan untuk menggambarkan...', '["A. Jaringan jalan raya", "B. Perairan (sungai, danau)", "C. Garis ketinggian (Kontur) dan bentang alam darat", "D. Hutan dan perkebunan"]'::jsonb, 'C. Garis ketinggian (Kontur) dan bentang alam darat'),
(15, 'Warna HIJAU pada peta topografi selalu mengindikasikan adanya...', '["A. Dataran tinggi", "B. Kawasan vegetasi / Hutan / Perkebunan", "C. Pemukiman padat", "D. Perbatasan negara"]'::jsonb, 'B. Kawasan vegetasi / Hutan / Perkebunan'),
(15, 'Warna BIRU pada peta digunakan secara universal untuk menyimbolkan unsur...', '["A. Udara", "B. Lapangan rumput", "C. Hidrografi / Perairan (Sungai, danau, rawa, laut)", "D. Batuan"]'::jsonb, 'C. Hidrografi / Perairan (Sungai, danau, rawa, laut)'),
(15, 'Warna MERAH pada peta topografi sering kali dikhususkan untuk menandakan unsur penting buatan manusia, yaitu...', '["A. Rel kereta api", "B. Jalan raya utama / aspal", "C. Kuburan", "D. Bandara"]'::jsonb, 'B. Jalan raya utama / aspal'),
(15, 'Warna HITAM dalam peta biasanya digunakan untuk mencetak...', '["A. Garis kontur", "B. Sungai", "C. Simbol pemukiman, gedung, jalan setapak, dan tulisan", "D. Batas wilayah udara"]'::jsonb, 'C. Simbol pemukiman, gedung, jalan setapak, dan tulisan'),
(15, 'Simbol berupa titik hitam dengan bentuk segitiga atau lingkaran disertai angka (misal: ▲ 2100) di peta menunjukkan...', '["A. Titik lokasi kemah", "B. Titik Triangulasi / Ketinggian mutlak (Spot Height)", "C. Posko pendaftaran", "D. Gunung berapi aktif"]'::jsonb, 'B. Titik Triangulasi / Ketinggian mutlak (Spot Height)'),
(15, 'Tindakan menyamakan posisi arah Utara pada peta agar sejajar dengan arah Utara sebenarnya di lapangan (menggunakan kompas) disebut...', '["A. Orientasi Peta", "B. Kalibrasi Peta", "C. Intersection", "D. Resection"]'::jsonb, 'A. Orientasi Peta'),
(15, 'Syarat pertama yang harus dilakukan sebelum melakukan teknik navigasi Resection atau Intersection di lapangan adalah...', '["A. Melipat peta", "B. Melakukan Orientasi Peta terlebih dahulu", "C. Menggambar kontur ulang", "D. Berjalan sejauh 1 km"]'::jsonb, 'B. Melakukan Orientasi Peta terlebih dahulu'),
(15, 'Teknik navigasi untuk menentukan titik koordinat posisi kita sendiri di atas peta, dengan cara membidik dua objek alam yang sudah diketahui di peta, disebut...', '["A. Orientasi", "B. Intersection", "C. Resection", "D. Proyeksi"]'::jsonb, 'C. Resection'),
(15, 'Teknik navigasi untuk mencari koordinat posisi objek lain (sasaran) yang belum diketahui di peta, dengan membidiknya dari dua titik stasiun yang berbeda, disebut...', '["A. Orientasi", "B. Intersection", "C. Resection", "D. Interpolasi"]'::jsonb, 'B. Intersection'),
(15, 'Alat ukur sederhana berbentuk busur derajat berbentuk kotak persegi transparan yang digunakan untuk menghitung sudut dan koordinat langsung di atas peta disebut...', '["A. Altimeter", "B. Curvimeter", "C. Penggaris biasa", "D. Protractor (Busur Peta)"]'::jsonb, 'D. Protractor (Busur Peta)'),
(15, 'Alat mekanis kecil dengan roda bergerigi yang dijalankan menyusuri rute lengkung di peta (seperti sungai atau jalan berliku) untuk menghitung jarak disebut...', '["A. Curvimeter", "B. Altimeter", "C. Protractor", "D. GPS"]'::jsonb, 'A. Curvimeter'),
(15, 'Penyimpangan sudut yang terjadi antara garis Utara Peta (Grid) dengan Utara Magnetis (Kompas) di suatu wilayah disebut...', '["A. Deklinasi Magnetis", "B. Inclinasi", "C. Deviasi Kompas", "D. Ikhtisar Peta"]'::jsonb, 'A. Deklinasi Magnetis'),
(15, 'Jika kita melipat peta topografi untuk dibawa di saku lapangan, cara melipat yang benar agar peta tidak cepat rusak dan mudah dibaca adalah...', '["A. Digulung menjadi silinder kecil", "B. Dilipat bebas sekecil mungkin", "C. Dilipat seperti kipas / akordion (zig-zag) dengan bagian yang akan dibaca menghadap luar", "D. Dipotong sesuai daerah yang dilewati"]'::jsonb, 'C. Dilipat seperti kipas / akordion (zig-zag) dengan bagian yang akan dibaca menghadap luar'),
(15, 'Saat membaca peta, jika kita berjalan mengikuti punggungan bukit (ridge), maka di peta kita sebenarnya sedang melangkah memotong garis-garis kontur yang berbentuk...', '["A. Lingkaran sempurna", "B. U atau V terbalik (menjorok ke bawah)", "C. Lurus", "D. Titik-titik"]'::jsonb, 'B. U atau V terbalik (menjorok ke bawah)'),
(15, 'Kumpulan peta dalam satu wujud buku besar dinamakan...', '["A. Atlas", "B. Globe", "C. Direktori", "D. Almanak"]'::jsonb, 'A. Atlas'),
(15, 'Jika tidak memiliki meteran, seorang Pramuka dapat memperkirakan jarak di peta dengan di lapangan menggunakan teknik...', '["A. Menghitung jumlah langkah kaki ganda (Pacing)", "B. Melempar batu", "C. Meneriakkan suara (Ema/Gema)", "D. Melihat warna daun"]'::jsonb, 'A. Menghitung jumlah langkah kaki ganda (Pacing)'),
(15, 'Garis Khatulistiwa (Equator) yang membelah bumi menjadi Utara dan Selatan ditarik pada derajat...', '["A. 0 derajat lintang", "B. 90 derajat bujur", "C. 180 derajat lintang", "D. 0 derajat bujur"]'::jsonb, 'A. 0 derajat lintang'),
(15, 'Garis Bujur Utama (Prime Meridian) yang menjadi titik 0 derajat dan patokan waktu bumi disepakati melintasi kota...', '["A. Washington DC, AS", "B. Paris, Prancis", "C. Greenwich, London, Inggris", "D. Tokyo, Jepang"]'::jsonb, 'C. Greenwich, London, Inggris'),
(15, 'Informasi mengenai tahun pembuatan atau pembaruan peta (update) biasanya dapat ditemukan di...', '["A. Pojok kiri atas", "B. Tengah peta", "C. Bagian tepi bawah luar / Margin bawah peta", "D. Di belakang peta"]'::jsonb, 'C. Bagian tepi bawah luar / Margin bawah peta'),
(15, 'Navigasi yang dilakukan di malam hari tanpa kompas dapat mengandalkan Rasi Bintang Pari (Crux) untuk menentukan arah...', '["A. Utara", "B. Selatan", "C. Timur", "D. Barat"]'::jsonb, 'B. Selatan'),
(15, 'Navigasi malam hari di belahan bumi utara/tengah dapat menentukan arah Utara dengan mencari konstelasi bintang...', '["A. Ursa Major (Bintang Biduk) / Polaris", "B. Sabuk Orion", "C. Bintang Pari", "D. Scorpius"]'::jsonb, 'A. Ursa Major (Bintang Biduk) / Polaris'),
(15, 'Alasan mengapa lumut pada pohon lebih sering tumbuh tebal di sisi tertentu (sebagai navigasi darurat penunjuk Timur/Barat) adalah...', '["A. Karena angin bertiup kencang", "B. Karena sisi tersebut adalah sisi yang paling sedikit atau paling banyak terkena paparan sinar matahari langsung (kondisi lembap)", "C. Karena tanahnya lebih subur", "D. Karena binatang suka bersarang di sana"]'::jsonb, 'B. Karena sisi tersebut adalah sisi yang paling sedikit atau paling banyak terkena paparan sinar matahari langsung (kondisi lembap)'),
(15, 'Metode navigasi alam menggunakan bayangan tongkat kayu yang ditancapkan tegak di tanah pada siang hari disebut metode...', '["A. Kompas alam", "B. Sundial / Metode Bayangan Matahari", "C. Resection alam", "D. Proyeksi bayangan"]'::jsonb, 'B. Sundial / Metode Bayangan Matahari'),
(15, 'Pada peta dengan sistem koordinat grid geografis, Lintang Utara disingkat dengan huruf...', '["A. LU (N - North)", "B. LS (S - South)", "C. BT (E - East)", "D. BB (W - West)"]'::jsonb, 'A. LU (N - North)'),
(15, 'Satu derajat (1°) dalam sistem koordinat Geografis (DMS) dibagi lagi menjadi...', '["A. 100 menit", "B. 60 menit", "C. 10 menit", "D. 360 menit"]'::jsonb, 'B. 60 menit'),
(15, 'Sistem Penentuan Posisi Global yang mengandalkan perangkat elektronik untuk menerima sinyal satelit navigasi bumi disebut...', '["A. Sonar", "B. Radar", "C. GPS (Global Positioning System)", "D. Kompas Digital"]'::jsonb, 'C. GPS (Global Positioning System)');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(15, 'Alat navigasi penunjuk arah angin yang bekerja berdasarkan gaya medan magnet bumi adalah...', '["A. Altimeter", "B. Kompas", "C. Barometer", "D. Sextant"]'::jsonb, 'B. Kompas'),
(15, 'Arah utara yang ditunjukkan oleh jarum kompas disebut...', '["A. Utara Sebenarnya (True North)", "B. Utara Magnetis (Magnetic North)", "C. Utara Peta (Grid North)", "D. Utara Kutub"]'::jsonb, 'B. Utara Magnetis (Magnetic North)'),
(15, 'Jenis kompas yang paling sering digunakan oleh Pramuka untuk membidik sasaran secara akurat karena dilengkapi prisma pembesar adalah...', '["A. Kompas Bidik (Prisma)", "B. Kompas Silva (Orientering)", "C. Kompas Geologi", "D. Kompas Bintang"]'::jsonb, 'A. Kompas Bidik (Prisma)'),
(15, 'Jenis kompas yang badannya tembus pandang dan sangat ideal digunakan di atas peta (biasa digunakan untuk olahraga Orienteering) adalah...', '["A. Kompas Bidik", "B. Kompas Silva", "C. Kompas Lensa", "D. Kompas Digital"]'::jsonb, 'B. Kompas Silva'),
(15, 'Bagian kompas bidik yang berupa benang/kawat halus untuk membidik sasaran agar tepat pada target disebut...', '["A. Visir", "B. Dial", "C. Kaca Pembesar", "D. Jarum Penunjuk"]'::jsonb, 'A. Visir'),
(15, 'Permukaan kompas di mana tertera angka derajat dan huruf mata angin disebut...', '["A. Visir", "B. Dial", "C. Kaca Pembesar", "D. Cincin Jempol"]'::jsonb, 'B. Dial'),
(15, 'Angka derajat untuk arah Timur (East) pada dial kompas adalah...', '["A. 0 derajat", "B. 90 derajat", "C. 180 derajat", "D. 270 derajat"]'::jsonb, 'B. 90 derajat'),
(15, 'Angka derajat untuk arah Selatan (South) pada dial kompas adalah...', '["A. 90 derajat", "B. 180 derajat", "C. 270 derajat", "D. 360 derajat"]'::jsonb, 'B. 180 derajat'),
(15, 'Arah Barat Daya terletak di antara Selatan dan Barat, dengan angka derajat...', '["A. 135 derajat", "B. 225 derajat", "C. 315 derajat", "D. 45 derajat"]'::jsonb, 'B. 225 derajat'),
(15, 'Tenggara adalah arah mata angin yang berada pada derajat...', '["A. 45 derajat", "B. 135 derajat", "C. 225 derajat", "D. 315 derajat"]'::jsonb, 'B. 135 derajat'),
(15, 'Cara memegang kompas bidik yang benar agar akurat adalah...', '["A. Diletakkan mendatar sejajar dada/mata dan tenang", "B. Dimiringkan 45 derajat", "C. Didekatkan tepat di depan hidung", "D. Dipegang lurus ke atas kepala"]'::jsonb, 'A. Diletakkan mendatar sejajar dada/mata dan tenang'),
(15, 'Sudut yang dibentuk antara arah Utara Magnetis dengan arah sasaran (target) yang kita bidik disebut...', '["A. Back Azimuth", "B. Azimuth", "C. Deklinasi", "D. Inclinasi"]'::jsonb, 'B. Azimuth'),
(15, 'Sasaran balik atau sudut balikan dari target ke titik kita berdiri disebut...', '["A. Deklinasi", "B. Azimuth", "C. Back Azimuth (Sasaran Balik)", "D. Resection"]'::jsonb, 'C. Back Azimuth (Sasaran Balik)'),
(15, 'Rumus untuk mencari Back Azimuth jika Azimuth bidikan LEBIH DARI 180 derajat adalah...', '["A. Azimuth + 180", "B. Azimuth - 180", "C. Azimuth + 90", "D. Azimuth - 90"]'::jsonb, 'B. Azimuth - 180'),
(15, 'Rumus untuk mencari Back Azimuth jika Azimuth bidikan KURANG DARI 180 derajat adalah...', '["A. Azimuth - 180", "B. Azimuth + 180", "C. Azimuth x 2", "D. Azimuth / 2"]'::jsonb, 'B. Azimuth + 180'),
(15, 'Jika kita membidik sebuah pohon dan didapat Azimuth 60 derajat, maka Back Azimuth-nya adalah...', '["A. 120 derajat", "B. 180 derajat", "C. 240 derajat", "D. 300 derajat"]'::jsonb, 'C. 240 derajat'),
(15, 'Jika target yang dibidik berada di arah 250 derajat, maka Back Azimuth-nya adalah...', '["A. 70 derajat", "B. 100 derajat", "C. 300 derajat", "D. 430 derajat"]'::jsonb, 'A. 70 derajat'),
(15, 'Teknik menentukan posisi kita yang belum diketahui di atas peta dengan cara membidik dua titik kenampakan alam yang sudah diketahui di peta disebut...', '["A. Intersection", "B. Resection", "C. Orientasi Peta", "D. Azimuth"]'::jsonb, 'B. Resection'),
(15, 'Teknik menentukan posisi suatu titik/benda lain yang belum diketahui di peta, dengan cara membidiknya dari dua titik stasiun yang berbeda, disebut...', '["A. Intersection", "B. Resection", "C. Eksplorasi", "D. Pemetaan"]'::jsonb, 'A. Intersection'),
(15, 'Penyimpangan sudut antara Utara Sebenarnya (True North) dan Utara Magnetik bumi disebut...', '["A. Deklinasi", "B. Inclinasi", "C. Deviasi", "D. Variasi"]'::jsonb, 'A. Deklinasi'),
(15, 'Penyimpangan jarum kompas karena adanya pengaruh logam atau magnet di sekitarnya disebut...', '["A. Deklinasi", "B. Resection", "C. Deviasi", "D. Inclinasi"]'::jsonb, 'C. Deviasi'),
(15, 'Gambar permukaan bumi yang diproyeksikan pada bidang datar dengan skala tertentu disebut...', '["A. Sketsa", "B. Maket", "C. Peta", "D. Denah"]'::jsonb, 'C. Peta'),
(15, 'Peta yang menggambarkan tinggi rendahnya permukaan bumi (relief) secara detail menggunakan garis-garis ketinggian disebut...', '["A. Peta Tematik", "B. Peta Topografi", "C. Peta Pita", "D. Peta Perjalanan"]'::jsonb, 'B. Peta Topografi'),
(15, 'Garis khayal pada peta topografi yang menghubungkan titik-titik dengan ketinggian yang sama disebut...', '["A. Garis Khatulistiwa", "B. Garis Bujur", "C. Garis Kontur", "D. Garis Lintang"]'::jsonb, 'C. Garis Kontur'),
(15, 'Ciri khas dari garis kontur adalah jika garis-garis tersebut jaraknya tergambar sangat rapat, itu menandakan daerah tersebut adalah...', '["A. Lereng yang landai", "B. Lembah yang datar", "C. Lereng yang terjal/curam", "D. Danau"]'::jsonb, 'C. Lereng yang terjal/curam'),
(15, 'Garis kontur yang bergerigi atau memiliki garis-garis kecil yang mengarah ke dalam biasanya menandakan...', '["A. Puncak gunung", "B. Kawah atau depresi (cekungan)", "C. Sungai", "D. Jalan raya"]'::jsonb, 'B. Kawah atau depresi (cekungan)'),
(15, 'Peta berskala 1 : 25.000 berarti 1 cm di peta mewakili jarak sebenarnya di lapangan sejauh...', '["A. 25 meter", "B. 250 meter", "C. 2.500 meter", "D. 25.000 meter (25 km)"]'::jsonb, 'B. 250 meter'),
(15, 'Jika jarak antara desa A dan B di peta dengan skala 1:50.000 adalah 4 cm, maka jarak sebenarnya adalah...', '["A. 2 km", "B. 4 km", "C. 20 km", "D. 200 km"]'::jsonb, 'A. 2 km'),
(15, 'Warna Hijau pada peta topografi standar biasanya melambangkan...', '["A. Perairan", "B. Pemukiman", "C. Vegetasi/Hutan", "D. Jalan raya"]'::jsonb, 'C. Vegetasi/Hutan'),
(15, 'Warna Biru pada peta topografi standar melambangkan...', '["A. Dataran tinggi", "B. Bentang air (sungai, danau, laut)", "C. Hutan", "D. Pemukiman"]'::jsonb, 'B. Bentang air (sungai, danau, laut)'),
(15, 'Peta khusus yang digambar oleh Pramuka saat melakukan perjalanan atau penjelajahan, digambar dari bawah ke atas pada kertas yang digulung, disebut...', '["A. Peta Topografi", "B. Peta Tematik", "C. Peta Pita", "D. Peta Bintang"]'::jsonb, 'C. Peta Pita'),
(15, 'Arah pembuatan dan penulisan Peta Pita selalu dimulai dari...', '["A. Kanan ke kiri", "B. Atas ke bawah", "C. Kiri ke kanan", "D. Bawah ke atas"]'::jsonb, 'D. Bawah ke atas'),
(15, 'Fungsi utama pembuatan Peta Pita adalah...', '["A. Sebagai alat ukur tinggi pohon", "B. Menggambarkan situasi dan kondisi rute perjalanan yang dilalui secara detail", "C. Untuk mencari letak gunung", "D. Menghitung luas wilayah"]'::jsonb, 'B. Menggambarkan situasi dan kondisi rute perjalanan yang dilalui secara detail'),
(15, 'Kolom yang biasanya TIDAK ADA dalam format standar Peta Pita adalah...', '["A. Kolom Waktu", "B. Kolom Cuaca", "C. Kolom Harga Tiket", "D. Kolom Arah (Azimuth)"]'::jsonb, 'C. Kolom Harga Tiket'),
(15, 'Untuk mengukur jarak saat membuat peta pita tanpa alat ukur meteran, Pramuka sering menggunakan metode...', '["A. Menghitung jumlah langkah kaki ganda/tunggal", "B. Menghitung durasi jam tangan", "C. Menerka dengan mata", "D. Menggunakan kecepatan angin"]'::jsonb, 'A. Menghitung jumlah langkah kaki ganda/tunggal'),
(15, 'Dalam Peta Pita, kolom "Keterangan/Kenampakan Alam" digunakan untuk menggambar...', '["A. Kompas", "B. Sketsa bangunan, pohon, jembatan, dan tanda medan yang dilihat di kiri-kanan jalan", "C. Wajah anggota regu", "D. Rencana menu makanan"]'::jsonb, 'B. Sketsa bangunan, pohon, jembatan, dan tanda medan yang dilihat di kiri-kanan jalan'),
(15, 'Jika kita tersesat di hutan pada siang hari tanpa kompas, arah matahari terbenam dapat digunakan sebagai patokan dasar arah...', '["A. Timur", "B. Barat", "C. Utara", "D. Selatan"]'::jsonb, 'B. Barat'),
(15, 'Tanda alam dari pohon yang bisa dijadikan panduan arah di hutan adalah...', '["A. Daun yang lebih hijau menunjuk ke Utara", "B. Lumut yang lebih tebal pada batang pohon biasanya mengarah ke matahari terbit (Timur) atau terbenam (Barat)", "C. Lumut yang lebih tebal di batang pohon biasanya berada di sisi yang jarang terkena matahari (menghadap Barat/Timur tergantung musim, tapi paling aman sisi berlumut lebat sering dihindari angin siang/menghadap lembab)", "D. Ranting yang lebih lebat dan panjang biasanya tumbuh ke arah yang banyak mendapat sinar matahari"]'::jsonb, 'D. Ranting yang lebih lebat dan panjang biasanya tumbuh ke arah yang banyak mendapat sinar matahari'),
(15, 'Bintang yang sering digunakan sebagai penunjuk arah Utara pada malam hari di belahan bumi utara/ekuator adalah...', '["A. Bintang Pari (Crux)", "B. Bintang Biduk (Ursa Major) / Polaris", "C. Bintang Kejora", "D. Sabuk Orion"]'::jsonb, 'B. Bintang Biduk (Ursa Major) / Polaris'),
(15, 'Rasi bintang yang bentuknya seperti layang-layang atau salib dan sering digunakan untuk mencari arah Selatan adalah...', '["A. Rasi Bintang Pari (Gubuk Penceng / Crux)", "B. Ursa Minor", "C. Cassiopeia", "D. Pegasus"]'::jsonb, 'A. Rasi Bintang Pari (Gubuk Penceng / Crux)'),
(15, 'Menyamakan posisi Utara pada peta dengan Utara sebenarnya di lapangan sebelum menggunakan peta disebut...', '["A. Navigasi", "B. Orientasi Peta", "C. Resection", "D. Azimuth"]'::jsonb, 'B. Orientasi Peta'),
(15, 'Alat bantu navigasi modern yang menggunakan konstelasi satelit untuk menentukan koordinat dan posisi di bumi adalah...', '["A. Radar", "B. Sonar", "C. GPS (Global Positioning System)", "D. Telegraf"]'::jsonb, 'C. GPS (Global Positioning System)'),
(15, 'Garis lintang 0 derajat yang membelah bumi menjadi bagian utara dan selatan disebut...', '["A. Garis Meridian Utama (Greenwich)", "B. Garis Khatulistiwa (Equator)", "C. Garis Balik Utara", "D. Garis Bujur"]'::jsonb, 'B. Garis Khatulistiwa (Equator)'),
(15, 'Garis bujur 0 derajat yang menjadi patokan waktu dunia terletak di kota...', '["A. London (Greenwich)", "B. Paris", "C. Washington DC", "D. Tokyo"]'::jsonb, 'A. London (Greenwich)'),
(15, 'Format koordinat Geografis yang umum digunakan dalam peta adalah...', '["A. Kilometer dan Meter", "B. Derajat, Menit, Detik (DMS)", "C. Mil dan Yard", "D. Sentimeter"]'::jsonb, 'B. Derajat, Menit, Detik (DMS)'),
(15, 'Saat membaca koordinat pada peta topografi dengan sistem UTM/Grid (Kotak), aturan dasar membacanya adalah...', '["A. Baca sumbu vertikal (Y) dulu, lalu horizontal (X)", "B. Baca ke arah Timur dulu (sumbu X), baru ke Utara (sumbu Y) / Easting lalu Northing", "C. Bebas dari mana saja", "D. Baca garis miring"]'::jsonb, 'B. Baca ke arah Timur dulu (sumbu X), baru ke Utara (sumbu Y) / Easting lalu Northing'),
(15, 'Titik ketinggian absolut suatu tempat yang tercetak di peta topografi (biasanya berupa segitiga atau titik dengan angka) disebut...', '["A. Spot Height (Titik Triangulasi)", "B. Kontur Indeks", "C. Interval", "D. Azimuth"]'::jsonb, 'A. Spot Height (Titik Triangulasi)'),
(15, 'Beda tinggi atau jarak vertikal antara satu garis kontur dengan garis kontur di sebelahnya disebut...', '["A. Spot Height", "B. Skala", "C. Kontur Interval", "D. Elevasi"]'::jsonb, 'C. Kontur Interval'),
(15, 'Alat bantu yang digunakan bersama peta untuk mengukur jarak sebenarnya dari rute melengkung/berbelok-belok (seperti sungai atau jalan) disebut...', '["A. Altimeter", "B. Curvimeter", "C. Planimeter", "D. Kompas"]'::jsonb, 'B. Curvimeter'),
(15, 'Hal yang paling penting dilakukan jika seorang Pramuka menyadari bahwa dirinya benar-benar tersesat di hutan adalah...', '["A. Berlari mencari jalan secepatnya", "B. Membuang barang bawaan", "C. STOP (Stop, Thinking, Observe, Plan) - Berhenti, Tenang, Amati, dan Rencanakan", "D. Memanjat pohon tertinggi saat itu juga"]'::jsonb, 'C. STOP (Stop, Thinking, Observe, Plan) - Berhenti, Tenang, Amati, dan Rencanakan');
INSERT INTO public.questions (chapter, question_text, options, correct_answer) VALUES
(24, 'Singkatan dari P3K adalah...', '["A. Pelatihan Pertama Pada Kecelakaan", "B. Pertolongan Pertama Pada Kecelakaan", "C. Pencegahan Pertama Pada Kecelakaan", "D. Penanganan Pasien Pada Kecelakaan"]'::jsonb, 'B. Pertolongan Pertama Pada Kecelakaan'),
(24, 'Tujuan utama dari pemberian P3K adalah...', '["A. Menggantikan tugas dokter", "B. Menyelamatkan nyawa dan mencegah kondisi korban memburuk", "C. Menyembuhkan penyakit kronis", "D. Memberikan obat dosis tinggi"]'::jsonb, 'B. Menyelamatkan nyawa dan mencegah kondisi korban memburuk'),
(24, 'Langkah pertama yang harus dilakukan saat menemukan korban kecelakaan adalah...', '["A. Langsung mengangkat korban", "B. Memastikan keamanan penolong, lokasi, dan korban (Aman Diri)", "C. Mencari identitas korban", "D. Memberi minum air putih"]'::jsonb, 'B. Memastikan keamanan penolong, lokasi, dan korban (Aman Diri)'),
(24, 'Pembalut segitiga yang sangat sering digunakan dalam P3K Pramuka disebut...', '["A. Plester", "B. Perban", "C. Mitela", "D. Kasa"]'::jsonb, 'C. Mitela'),
(24, 'Alat keras/kaku yang digunakan untuk menahan tulang yang patah agar tidak bergerak disebut...', '["A. Mitela", "B. Bidai / Spalk", "C. Tourniquet", "D. Tanduk"]'::jsonb, 'B. Bidai / Spalk'),
(24, 'Pertolongan pertama pada korban mimisan yang benar adalah...', '["A. Menengadahkan kepala ke belakang", "B. Menundukkan kepala ke depan dan menjepit cuping hidung", "C. Memasukkan kapas ke dalam hidung", "D. Menyiram wajah dengan air es"]'::jsonb, 'B. Menundukkan kepala ke depan dan menjepit cuping hidung'),
(24, 'Pendarahan arteri ditandai dengan ciri-ciri...', '["A. Darah merembes pelan", "B. Darah memancar seirama denyut jantung dan berwarna merah terang", "C. Darah berwarna merah gelap dan mengalir", "D. Darah tidak keluar"]'::jsonb, 'B. Darah memancar seirama denyut jantung dan berwarna merah terang'),
(24, 'Cara menghentikan pendarahan luar yang paling efektif adalah dengan teknik...', '["A. Balut tekan (tekan langsung di atas luka)", "B. Disiram air mengalir", "C. Diberi bedak", "D. Diikat dengan tali"]'::jsonb, 'A. Balut tekan (tekan langsung di atas luka)'),
(24, 'Simpul yang digunakan untuk mengakhiri balutan mitela agar mudah dilepas adalah...', '["A. Simpul Pangkal", "B. Simpul Mati", "C. Simpul Hidup", "D. Simpul Jangkar"]'::jsonb, 'B. Simpul Mati'),
(24, 'Kondisi penurunan suhu tubuh secara drastis akibat cuaca dingin di gunung disebut...', '["A. Hipertermia", "B. Hipotermia", "C. Dehidrasi", "D. Anemia"]'::jsonb, 'B. Hipotermia'),
(24, 'Pertolongan pertama pada luka bakar ringan (derajat 1) adalah...', '["A. Diolesi odol / pasta gigi", "B. Dialiri air bersih mengalir selama 10-15 menit", "C. Diolesi mentega", "D. Diberi kecap"]'::jsonb, 'B. Dialiri air bersih mengalir selama 10-15 menit'),
(24, 'Alat untuk mengangkut korban kecelakaan secara darurat yang dibuat dari dua tongkat dan tali disebut...', '["A. Bivak", "B. Tandu Darurat (Dragbar)", "C. Kereta dorong", "D. Rakit"]'::jsonb, 'B. Tandu Darurat (Dragbar)'),
(24, 'Jumlah ikatan minimal pada pemasangan bidai untuk patah tulang tungkai bawah adalah...', '["A. 1 ikatan", "B. 2 ikatan", "C. 3 ikatan", "D. Minimal melewati dua sendi"]'::jsonb, 'D. Minimal melewati dua sendi'),
(24, 'Korban pingsan sebaiknya diposisikan telentang dengan posisi kaki...', '["A. Lebih rendah dari kepala", "B. Sejajar dengan kepala", "C. Lebih tinggi dari kepala (Elevasi)", "D. Dilipat"]'::jsonb, 'C. Lebih tinggi dari kepala (Elevasi)'),
(24, 'Isi kotak P3K yang berfungsi untuk membersihkan luka dari kuman adalah...', '["A. Kapas", "B. Antiseptik (Betadine/Rivanol)", "C. Gunting", "D. Balsem"]'::jsonb, 'B. Antiseptik (Betadine/Rivanol)'),
(24, 'Penyakit yang disebabkan oleh gigitan nyamuk Aedes Aegypti adalah...', '["A. Malaria", "B. Demam Berdarah (Dengue)", "C. Tifus", "D. Diare"]'::jsonb, 'B. Demam Berdarah (Dengue)'),
(24, 'Cara menangani kaki yang terkilir (kram/keseleo) dengan metode RICE, singkatan dari...', '["A. Run, Ice, Compression, Eat", "B. Rest, Ice, Compression, Elevation", "C. Rest, Iron, Cold, Energy", "D. Race, Ice, Cool, End"]'::jsonb, 'B. Rest, Ice, Compression, Elevation'),
(24, 'Pertolongan pertama jika seseorang tersedak makanan dan sulit bernapas adalah dengan...', '["A. Memberi minum air", "B. Manuver Heimlich (hentakan pada perut)", "C. Menidurkan korban", "D. Memukul kepala"]'::jsonb, 'B. Manuver Heimlich (hentakan pada perut)'),
(24, 'Obat yang digunakan untuk mengurangi rasa sakit kepala atau demam ringan adalah...', '["A. Antasida", "B. Parasetamol", "C. Oralit", "D. Entrostop"]'::jsonb, 'B. Parasetamol'),
(24, 'Untuk mengganti cairan tubuh yang hilang akibat diare, sebaiknya diberikan...', '["A. Air es", "B. Oralit", "C. Kopi", "D. Susu"]'::jsonb, 'B. Oralit'),
(24, 'Pembalutan pada luka di kepala biasanya menggunakan mitela yang dilipat menjadi bentuk...', '["A. Pita", "B. Segitiga terbuka", "C. Kantong", "D. Topi"]'::jsonb, 'B. Segitiga terbuka'),
(24, 'Luka yang disebabkan oleh benda tumpul dan menyebabkan memar kebiruan disebut luka...', '["A. Luka Sayat", "B. Luka Memar (Contusio)", "C. Luka Tusuk", "D. Luka Bakar"]'::jsonb, 'B. Luka Memar (Contusio)'),
(24, 'Tindakan RJP (Resusitasi Jantung Paru) dilakukan pada korban yang...', '["A. Luka lecet", "B. Henti napas dan henti jantung", "C. Patah tulang", "D. Pusing"]'::jsonb, 'B. Henti napas dan henti jantung'),
(24, 'Pada saat memindahkan korban dengan tandu, posisi kepala korban sebaiknya berada di...', '["A. Depan (arah jalan)", "B. Belakang (berlawanan arah jalan)", "C. Samping kiri", "D. Samping kanan"]'::jsonb, 'B. Belakang (berlawanan arah jalan)'),
(24, 'Warna kotak P3K standar biasanya adalah...', '["A. Merah", "B. Putih dengan tanda palang merah/hijau", "C. Kuning", "D. Hitam"]'::jsonb, 'B. Putih dengan tanda palang merah/hijau'),
(24, 'Pertolongan pertama pada gigitan ular yang paling tepat adalah...', '["A. Mengisap racun dengan mulut", "B. Mengikat sangat kuat (tourniquet)", "C. Imobilisasi (tidak menggerakkan bagian yang digigit) dan bawa ke RS", "D. Membelah luka"]'::jsonb, 'C. Imobilisasi (tidak menggerakkan bagian yang digigit) dan bawa ke RS'),
(24, 'Pembalut elastis (Elastic Bandage) sangat baik digunakan untuk menangani...', '["A. Luka bakar", "B. Terkilir / Cedera sendi", "C. Pendarahan hebat", "D. Luka tusuk"]'::jsonb, 'B. Terkilir / Cedera sendi'),
(24, 'Penyakit yang sering muncul di perkemahan akibat sanitasi buruk dan air kotor adalah...', '["A. Asma", "B. Diare", "C. Jantung", "D. Rabies"]'::jsonb, 'B. Diare'),
(24, 'Kasa steril diletakkan langsung di atas luka bertujuan untuk...', '["A. Mendinginkan luka", "B. Menutup luka agar tidak infeksi dan menyerap darah", "C. Menghilangkan rasa sakit", "D. Meluruskan tulang"]'::jsonb, 'B. Menutup luka agar tidak infeksi dan menyerap darah'),
(24, 'Berapa jumlah penolong yang ideal untuk mengangkat tandu darurat?', '["A. 1 orang", "B. 2-4 orang", "C. 10 orang", "D. 12 orang"]'::jsonb, 'B. 2-4 orang'),
(24, 'Alat untuk mengukur suhu tubuh manusia disebut...', '["A. Barometer", "B. Termometer", "C. Altimeter", "D. Kompas"]'::jsonb, 'B. Termometer'),
(24, 'Suhu tubuh normal manusia berkisar antara...', '["A. 30-32 derajat", "B. 36-37 derajat", "C. 39-40 derajat", "D. 42-45 derajat"]'::jsonb, 'B. 36-37 derajat'),
(24, 'Tindakan yang harus dihindari saat menolong korban patah tulang adalah...', '["A. Memasang bidai", "B. Mencoba meluruskan posisi tulang secara paksa", "C. Mengurangi gerakan", "D. Memanggil bantuan"]'::jsonb, 'B. Mencoba meluruskan posisi tulang secara paksa'),
(24, 'Mencuci tangan sebelum makan dan setelah beraktivitas merupakan contoh...', '["A. Pengobatan", "B. Perilaku Hidup Bersih dan Sehat (PHBS)", "C. Olahraga", "D. Keterampilan P3K"]'::jsonb, 'B. Perilaku Hidup Bersih dan Sehat (PHBS)'),
(24, 'Cairan yang digunakan untuk mencuci mata jika kemasukan debu adalah...', '["A. Alkohol", "B. Air bersih / Boorwater", "C. Antiseptik", "D. Minyak kayu putih"]'::jsonb, 'B. Air bersih / Boorwater'),
(24, 'Pembalut Mitela dilipat menjadi "Gendongan" berfungsi untuk menyangga cedera pada...', '["A. Kaki", "B. Lengan / Bahu", "C. Kepala", "D. Perut"]'::jsonb, 'B. Lengan / Bahu'),
(24, 'Tanda-tanda seseorang mengalami syok (shock) adalah...', '["A. Wajah memerah", "B. Nadi cepat dan lemah, kulit pucat, keringat dingin", "C. Badan sangat panas", "D. Tertawa terus"]'::jsonb, 'B. Nadi cepat dan lemah, kulit pucat, keringat dingin'),
(24, 'Zat racun dalam makanan dapat dinetralkan sementara (sebelum ke dokter) dengan meminum...', '["A. Susu / Air kelapa", "B. Air soda", "C. Kopi hitam", "D. Jus jeruk"]'::jsonb, 'A. Susu / Air kelapa'),
(24, 'Obat luar yang digunakan untuk meredakan gatal akibat gigitan serangga adalah...', '["A. Oralit", "B. Minyak Kayu Putih / Kaladin", "C. Parasetamol", "D. Antasida"]'::jsonb, 'B. Minyak Kayu Putih / Kaladin'),
(24, 'Luka tusuk akibat paku berkarat sangat berisiko menyebabkan penyakit...', '["A. Rabies", "B. Tetanus", "C. Polio", "D. Tifus"]'::jsonb, 'B. Tetanus'),
(24, 'Pada RJP (CPR), rasio kompresi dada dan napas buatan untuk satu penolong adalah...', '["A. 15 : 2", "B. 30 : 2", "C. 5 : 1", "D. 10 : 1"]'::jsonb, 'B. 30 : 2'),
(24, 'Pembalutan luka di lutut yang sedang ditekuk paling baik menggunakan teknik...', '["A. Balutan angka delapan", "B. Balutan lurus", "C. Balutan melingkar", "D. Plester saja"]'::jsonb, 'A. Balutan angka delapan'),
(24, 'Bagian dari tas P3K yang digunakan untuk memotong perban atau pakaian korban adalah...', '["A. Pisau", "B. Gunting", "C. Silet", "D. Tang"]'::jsonb, 'B. Gunting'),
(24, 'Untuk membersihkan luka yang kotor dari kerikil atau pasir digunakan...', '["A. Kapas", "B. Pinset dan air bersih", "C. Tangan langsung", "D. Kain kotor"]'::jsonb, 'B. Pinset dan air bersih'),
(24, 'Apa yang harus dilakukan jika korban tersambar petir?', '["A. Jangan disentuh karena ada listrik", "B. Segera periksa napas dan nadi, lakukan RJP jika perlu, dan bawa ke RS", "C. Disiram air", "D. Dikubur di dalam tanah"]'::jsonb, 'B. Segera periksa napas dan nadi, lakukan RJP jika perlu, dan bawa ke RS'),
(24, 'Gunting yang bagian ujungnya tumpul (Gunting Verban) bertujuan untuk...', '["A. Tidak tajam", "B. Mencegah kulit korban terluka saat menggunting perban", "C. Menghias perban", "D. Memotong kawat"]'::jsonb, 'B. Mencegah kulit korban terluka saat menggunting perban'),
(24, 'Kesehatan lingkungan perkemahan dijaga dengan cara membuat lubang sampah sedalam...', '["A. 10 cm", "B. 50-100 cm (agar tidak dibongkar hewan)", "C. 2 meter", "D. Tidak perlu lubang"]'::jsonb, 'B. 50-100 cm (agar tidak dibongkar hewan)'),
(24, 'Obat yang digunakan untuk menolong sakit perut akibat maag adalah...', '["A. Parasetamol", "B. Antasida", "C. Oralit", "D. Betadine"]'::jsonb, 'B. Antasida'),
(24, 'Mencuci luka dengan air sabun sangat disarankan khusus untuk luka akibat...', '["A. Teriris pisau", "B. Gigitan hewan (anjing/kucing) untuk cegah rabies", "C. Luka bakar", "D. Luka tusuk"]'::jsonb, 'B. Gigitan hewan (anjing/kucing) untuk cegah rabies'),
(24, 'Prinsip utama penolong P3K adalah...', '["A. Cepat dan Terburu-buru", "B. Tenang, Cepat, Tepat, dan Tidak Panik", "C. Menunggu dokter datang", "D. Berteriak minta tolong"]'::jsonb, 'B. Tenang, Cepat, Tepat, dan Tidak Panik');